const e=JSON.parse(`[{"english":"airport","georgian":"бғҗбғ”бғ бғқбғһбғқбғ бғўбғҳ","pronunciation":"/ЛҲЙӣrpЙ”Лҗrt/","example_en":"We arrived at the airport early.","example_ka":"бғҗбғ”бғ бғқбғһбғқбғ бғўбғЁбғҳ бғҗбғ“бғ бғ” бғӣбғҳбғ•бғ”бғ“бғҳбғ—.","category":"travel-transport","level":"A1"},{"english":"airplane","georgian":"бғ—бғ•бғҳбғ—бғӣбғӨбғ бғҳбғңбғҗбғ•бғҳ","pronunciation":"/ЛҲЙӣrpleЙӘn/","example_en":"The airplane takes off in an hour.","example_ka":"бғ—бғ•бғҳбғ—бғӣбғӨбғ бғҳбғңбғҗбғ•бғҳ бғ”бғ бғ— бғЎбғҗбғҗбғ—бғЁбғҳ бғ’бғҗбғӨбғ бғҳбғңбғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"A1"},{"english":"ticket","georgian":"бғ‘бғҳбғҡбғ”бғ—бғҳ","pronunciation":"/ЛҲtЙӘkЙӘt/","example_en":"I bought a one-way ticket.","example_ka":"бғӘбғҗбғҡбғӣбғ®бғ бғҳбғ•бғҳ бғ‘бғҳбғҡбғ”бғ—бғҳ бғ•бғҳбғ§бғҳбғ“бғ”.","category":"travel-transport","level":"A1"},{"english":"passport","georgian":"бғһбғҗбғЎбғһбғқбғ бғўбғҳ","pronunciation":"/ЛҲpГҰspЙ”Лҗrt/","example_en":"Don't forget your passport.","example_ka":"бғһбғҗбғЎбғһбғқбғ бғўбғҳ бғҗбғ  бғ“бғҗбғ’бғҗбғ•бғҳбғ¬бғ§бғ“бғ”бғЎ.","category":"travel-transport","level":"A1"},{"english":"visa","georgian":"бғ•бғҳбғ–бғҗ","pronunciation":"/ЛҲviЛҗzЙҷ/","example_en":"You need a visa to enter this country.","example_ka":"бғҗбғӣ бғҘбғ•бғ”бғ§бғҗбғңбғҗбғЁбғҳ бғЁбғ”бғЎбғҗбғЎбғ•бғҡбғ”бғҡбғҗбғ“ бғ•бғҳбғ–бғҗ бғ’бғӯбғҳбғ бғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"A2"},{"english":"luggage","georgian":"бғ‘бғҗбғ бғ’бғҳ","pronunciation":"/ЛҲlКҢЙЎЙӘdК’/","example_en":"My luggage is very heavy.","example_ka":"бғ©бғ”бғӣбғҳ бғ‘бғҗбғ бғ’бғҳ бғ«бғҗбғҡбғҳбғҗбғң бғӣбғ«бғҳбғӣбғ”бғҗ.","category":"travel-transport","level":"A1"},{"english":"suitcase","georgian":"бғ©бғ”бғӣбғқбғ“бғҗбғңбғҳ","pronunciation":"/ЛҲsuЛҗtkeЙӘs/","example_en":"Pack your suitcase tonight.","example_ka":"бғ©бғ”бғӣбғқбғ“бғҗбғңбғҳ бғ“бғҰбғ”бғЎ бғЎбғҗбғҰбғҗбғӣбғқбғЎ бғ©бғҗбғҡбғҗбғ’бғ”.","category":"travel-transport","level":"A1"},{"english":"departure","georgian":"бғ’бғҗбғӣбғ’бғ–бғҗбғ•бғ бғ”бғ‘бғҗ","pronunciation":"/dЙӘЛҲpЙ‘ЛҗrtКғЙҷr/","example_en":"The departure is delayed by two hours.","example_ka":"бғ’бғҗбғӣбғ’бғ–бғҗбғ•бғ бғ”бғ‘бғҗ бғқбғ бғҳ бғЎбғҗбғҗбғ—бғҳбғ— бғ’бғҗбғ“бғҗбғҳбғ“бғқ.","category":"travel-transport","level":"A2"},{"english":"arrival","georgian":"бғ©бғҗбғӣбғқбғЎбғ•бғҡбғҗ","pronunciation":"/ЙҷЛҲraЙӘvЙҷl/","example_en":"Check the arrival time.","example_ka":"бғ©бғҗбғӣбғқбғЎбғ•бғҡбғҳбғЎ бғ“бғ бғқ бғЁбғ”бғҗбғӣбғқбғ¬бғӣбғ”.","category":"travel-transport","level":"A2"},{"english":"flight","georgian":"бғӨбғ бғ”бғңбғҗ","pronunciation":"/flaЙӘt/","example_en":"The flight to London takes four hours.","example_ka":"бғҡбғқбғңбғ“бғқбғңбғЁбғҳ бғӨбғ бғ”бғңбғҗ бғқбғ—бғ® бғЎбғҗбғҗбғ—бғЎ бғ’бғ бғ«бғ”бғҡбғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"A1"},{"english":"hotel","georgian":"бғЎбғҗбғЎбғўбғЈбғӣбғ бғқ","pronunciation":"/hoКҠЛҲtЙӣl/","example_en":"We booked a hotel near the beach.","example_ka":"бғЎбғҗбғңбғҗбғһбғҳбғ бғқбғЎбғ—бғҗбғң бғЎбғҗбғЎбғўбғЈбғӣбғ бғқ бғ“бғҗбғ•бғҜбғҗбғ•бғЁбғңбғ”бғ—.","category":"travel-transport","level":"A1"},{"english":"reservation","georgian":"бғҜбғҗбғ•бғЁбғҗбғңбғҳ","pronunciation":"/ЛҢrЙӣzЙҷrЛҲveЙӘКғЙҷn/","example_en":"I have a reservation for two nights.","example_ka":"бғқбғ бғҳ бғҰбғҗбғӣбғҳбғ— бғҜбғҗбғ•бғЁбғҗбғңбғҳ бғӣбғҗбғҘбғ•бғЎ.","category":"travel-transport","level":"A2"},{"english":"car","georgian":"бғӣбғҗбғңбғҘбғҗбғңбғҗ","pronunciation":"/kЙ‘Лҗr/","example_en":"I drive a car to work.","example_ka":"бғЎбғҗбғӣбғЎбғҗбғ®бғЈбғ бғЁбғҳ бғӣбғҗбғңбғҘбғҗбғңбғҳбғ— бғӣбғҳбғ•бғ“бғҳбғ•бғҗбғ .","category":"travel-transport","level":"A1"},{"english":"bus","georgian":"бғҗбғ•бғўбғқбғ‘бғЈбғЎбғҳ","pronunciation":"/bКҢs/","example_en":"The bus arrives every ten minutes.","example_ka":"бғҗбғ•бғўбғқбғ‘бғЈбғЎбғҳ бғ§бғқбғ•бғ”бғҡ бғҗбғ— бғ¬бғЈбғ—бғЁбғҳ бғӣбғқбғ“бғҳбғЎ.","category":"travel-transport","level":"A1"},{"english":"train","georgian":"бғӣбғҗбғўбғҗбғ бғ”бғ‘бғ”бғҡбғҳ","pronunciation":"/treЙӘn/","example_en":"We took the train to Batumi.","example_ka":"бғ‘бғҗбғ—бғЈбғӣбғЁбғҳ бғӣбғҗбғўбғҗбғ бғ”бғ‘бғҡбғҳбғ— бғ¬бғҗбғ•бғ”бғ“бғҳбғ—.","category":"travel-transport","level":"A1"},{"english":"taxi","georgian":"бғўбғҗбғҘбғЎбғҳ","pronunciation":"/ЛҲtГҰksi/","example_en":"Call a taxi, please.","example_ka":"бғўбғҗбғҘбғЎбғҳ бғ’бғҗбғӣбғқбғҳбғ«бғҗбғ®бғ”, бғ’бғ—бғ®бғқбғ•бғ—.","category":"travel-transport","level":"A1"},{"english":"subway","georgian":"бғӣбғ”бғўбғ бғқ","pronunciation":"/ЛҲsКҢbweЙӘ/","example_en":"The subway is the fastest way.","example_ka":"бғӣбғ”бғўбғ бғқ бғ§бғ•бғ”бғҡбғҗбғ–бғ” бғЎбғ¬бғ бғҗбғӨбғҳ бғ’бғ–бғҗбғҗ.","category":"travel-transport","level":"A1"},{"english":"bicycle","georgian":"бғ•бғ”бғҡбғқбғЎбғҳбғһбғ”бғ“бғҳ","pronunciation":"/ЛҲbaЙӘsЙӘkЙҷl/","example_en":"I ride my bicycle to school.","example_ka":"бғЎбғҷбғқбғҡбғҗбғЁбғҳ бғ•бғ”бғҡбғқбғЎбғҳбғһбғ”бғ“бғҳбғ— бғӣбғҳбғ•бғ“бғҳбғ•бғҗбғ .","category":"travel-transport","level":"A1"},{"english":"motorcycle","georgian":"бғӣбғқбғўбғқбғӘбғҳбғҷбғҡбғҳ","pronunciation":"/ЛҲmoКҠtЙҷrЛҢsaЙӘkЙҷl/","example_en":"He bought a new motorcycle.","example_ka":"бғӣбғҗбғң бғҗбғ®бғҗбғҡбғҳ бғӣбғқбғўбғқбғӘбғҳбғҷбғҡбғҳ бғҳбғ§бғҳбғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"ship","georgian":"бғ’бғ”бғӣбғҳ","pronunciation":"/КғЙӘp/","example_en":"The ship sailed across the sea.","example_ka":"бғ’бғ”бғӣбғҳ бғ–бғҰбғ•бғҗбғЁбғҳ бғ’бғҗбғ•бғҳбғ“бғҗ.","category":"travel-transport","level":"A1"},{"english":"boat","georgian":"бғңбғҗбғ•бғҳ","pronunciation":"/boКҠt/","example_en":"We rented a small boat.","example_ka":"бғһбғҗбғўбғҗбғ бғҗ бғңбғҗбғ•бғҳ бғ“бғҗбғ•бғҳбғҘбғҳбғ бғҗбғ•бғ”бғ—.","category":"travel-transport","level":"A1"},{"english":"road","georgian":"бғ’бғ–бғҗ","pronunciation":"/roКҠd/","example_en":"The road is very long.","example_ka":"бғ’бғ–бғҗ бғ«бғҗбғҡбғҳбғҗбғң бғ’бғ бғ«бғ”бғҡбғҳбғҗ.","category":"travel-transport","level":"A1"},{"english":"highway","georgian":"бғҗбғ•бғўбғқбғӣбғҗбғ’бғҳбғЎбғўбғ бғҗбғҡбғҳ","pronunciation":"/ЛҲhaЙӘweЙӘ/","example_en":"The highway connects the two cities.","example_ka":"бғҗбғ•бғўбғқбғӣбғҗбғ’бғҳбғЎбғўбғ бғҗбғҡбғҳ бғқбғ  бғҘбғҗбғҡбғҗбғҘбғЎ бғҗбғҷбғҗбғ•бғЁбғҳбғ бғ”бғ‘бғЎ.","category":"travel-transport","level":"B1"},{"english":"bridge","georgian":"бғ®бғҳбғ“бғҳ","pronunciation":"/brЙӘdК’/","example_en":"Cross the bridge to get there.","example_ka":"бғҳбғҘ бғӣбғҳбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғҗбғ“ бғ®бғҳбғ“бғҳ бғ’бғҗбғ“бғҗбғҡбғҗбғ®бғ”.","category":"travel-transport","level":"A2"},{"english":"traffic","georgian":"бғЎбғҗбғӘбғқбғ‘бғҳ","pronunciation":"/ЛҲtrГҰfЙӘk/","example_en":"There is heavy traffic in the morning.","example_ka":"бғ“бғҳбғҡбғҳбғ— бғ“бғҳбғ“бғҳ бғЎбғҗбғӘбғқбғ‘бғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"parking","georgian":"бғһбғҗбғ бғҷбғҳбғңбғ’бғҳ","pronunciation":"/ЛҲpЙ‘ЛҗrkЙӘЕӢ/","example_en":"Is there parking near the hotel?","example_ka":"бғЎбғҗбғЎбғўбғЈбғӣбғ бғқбғЎбғ—бғҗбғң бғһбғҗбғ бғҷбғҳбғңбғ’бғҳ бғҗбғ бғҳбғЎ?","category":"travel-transport","level":"A2"},{"english":"map","georgian":"бғ бғЈбғҷбғҗ","pronunciation":"/mГҰp/","example_en":"Look at the map to find the way.","example_ka":"бғ’бғ–бғҳбғЎ бғЎбғҗбғһбғқбғ•бғңбғ”бғҡбғҗбғ“ бғ бғЈбғҷбғҗбғЎ бғЁбғ”бғ®бғ”бғ“бғ”.","category":"travel-transport","level":"A1"},{"english":"direction","georgian":"бғӣбғҳбғӣбғҗбғ бғ—бғЈбғҡбғ”бғ‘бғҗ","pronunciation":"/dЙӘЛҲrЙӣkКғЙҷn/","example_en":"Can you give me directions?","example_ka":"бғӣбғҳбғӣбғҗбғ бғ—бғЈбғҡбғ”бғ‘бғҗбғЎ бғӣбғҳбғ—бғ®бғ бғқбғ‘?","category":"travel-transport","level":"A2"},{"english":"left","georgian":"бғӣбғҗбғ бғӘбғ®бғңбғҳбғ•","pronunciation":"/lЙӣft/","example_en":"Turn left at the corner.","example_ka":"бғҷбғЈбғ—бғ®бғ”бғЁбғҳ бғӣбғҗбғ бғӘбғ®бғңбғҳбғ• бғӣбғқбғЈбғ®бғ•бғҳбғ”.","category":"travel-transport","level":"A1"},{"english":"right","georgian":"бғӣбғҗбғ бғҜбғ•бғңбғҳбғ•","pronunciation":"/raЙӘt/","example_en":"Turn right after the bridge.","example_ka":"бғ®бғҳбғ“бғҳбғЎ бғЁбғ”бғӣбғ“бғ”бғ’ бғӣбғҗбғ бғҜбғ•бғңбғҳбғ• бғӣбғқбғЈбғ®бғ•бғҳбғ”.","category":"travel-transport","level":"A1"},{"english":"straight","georgian":"бғһбғҳбғ бғ“бғҗбғһбғҳбғ ","pronunciation":"/streЙӘt/","example_en":"Go straight for two blocks.","example_ka":"бғқбғ бғҳ бғҷбғ•бғҗбғ бғўбғҗбғҡбғҳ бғһбғҳбғ бғ“бғҗбғһбғҳбғ  бғ¬бғҗбғ“бғҳ.","category":"travel-transport","level":"A1"},{"english":"corner","georgian":"бғҷбғЈбғ—бғ®бғ”","pronunciation":"/ЛҲkЙ”ЛҗrnЙҷr/","example_en":"The shop is on the corner.","example_ka":"бғӣбғҗбғҰбғҗбғ–бғҳбғҗ бғҷбғЈбғ—бғ®бғ”бғЁбғҳбғҗ.","category":"travel-transport","level":"A1"},{"english":"stop","georgian":"бғ’бғҗбғ©бғ”бғ бғ”бғ‘бғҗ","pronunciation":"/stЙ‘Лҗp/","example_en":"The bus stop is over there.","example_ka":"бғҗбғ•бғўбғқбғ‘бғЈбғЎбғҳбғЎ бғ’бғҗбғ©бғ”бғ бғ”бғ‘бғҗ бғҳбғҘ бғҗбғ бғҳбғЎ.","category":"travel-transport","level":"A1"},{"english":"station","georgian":"бғЎбғҗбғ“бғ’бғЈбғ бғҳ","pronunciation":"/ЛҲsteЙӘКғЙҷn/","example_en":"Meet me at the train station.","example_ka":"бғӣбғҗбғўбғҗбғ бғ”бғ‘бғҡбғҳбғЎ бғЎбғҗбғ“бғ’бғЈбғ бғ–бғ” бғЁбғ”бғӣбғ®бғ•бғ“бғҳ.","category":"travel-transport","level":"A1"},{"english":"tourist","georgian":"бғўбғЈбғ бғҳбғЎбғўбғҳ","pronunciation":"/ЛҲtКҠrЙӘst/","example_en":"Many tourists visit Georgia.","example_ka":"бғ‘бғ”бғ•бғ бғҳ бғўбғЈбғ бғҳбғЎбғўбғҳ бғ”бғ¬бғ•бғ”бғ•бғҗ бғЎбғҗбғҘбғҗбғ бғ—бғ•бғ”бғҡбғқбғЎ.","category":"travel-transport","level":"A1"},{"english":"guide","georgian":"бғ’бғҳбғ“бғҳ","pronunciation":"/ЙЎaЙӘd/","example_en":"The guide showed us the old town.","example_ka":"бғ’бғҳбғ“бғӣбғҗ бғ«бғ•бғ”бғҡбғҳ бғҘбғҗбғҡбғҗбғҘбғҳ бғ“бғҗбғ’бғ•бғҗбғ—бғ•бғҗбғҡбғҳбғ”бғ бғ”бғ‘бғҳбғңбғҗ.","category":"travel-transport","level":"A2"},{"english":"trip","georgian":"бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗ","pronunciation":"/trЙӘp/","example_en":"We had a wonderful trip.","example_ka":"бғЁбғ”бғЎбғҗбғңбғҳбғЁбғңбғҗбғ•бғҳ бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗ бғ’бғ•бғҘбғқбғңбғ“бғҗ.","category":"travel-transport","level":"A1"},{"english":"journey","georgian":"бғ’бғ–бғҗ","pronunciation":"/ЛҲdК’ЙңЛҗrni/","example_en":"The journey took five hours.","example_ka":"бғ’бғ–бғҗ бғ®бғЈбғ— бғЎбғҗбғҗбғ—бғЎ бғ’бғҗбғ’бғ бғ«бғ”бғҡбғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"vacation","georgian":"бғЁбғ•бғ”бғ‘бғЈбғҡбғ”бғ‘бғҗ","pronunciation":"/veЙӘЛҲkeЙӘКғЙҷn/","example_en":"We're going on vacation next week.","example_ka":"бғӣбғқбғӣбғҗбғ•бғҗбғҡ бғҷбғ•бғҳбғ бғҗбғЎ бғЁбғ•бғ”бғ‘бғЈбғҡбғ”бғ‘бғҗбғЁбғҳ бғӣбғҳбғ•бғ“бғҳбғ•бғҗбғ бғ—.","category":"travel-transport","level":"A1"},{"english":"souvenir","georgian":"бғЎбғЈбғ•бғ”бғңбғҳбғ бғҳ","pronunciation":"/ЛҢsuЛҗvЙҷЛҲnЙӘr/","example_en":"I bought souvenirs for my family.","example_ka":"бғқбғҜбғҗбғ®бғҳбғЎбғ—бғ•бғҳбғЎ бғЎбғЈбғ•бғ”бғңбғҳбғ бғ”бғ‘бғҳ бғ•бғҳбғ§бғҳбғ“бғ”.","category":"travel-transport","level":"A2"},{"english":"currency","georgian":"бғ•бғҗбғҡбғЈбғўбғҗ","pronunciation":"/ЛҲkКҢrЙҷnsi/","example_en":"What currency do they use?","example_ka":"бғ бғҗ бғ•бғҗбғҡбғЈбғўбғҗбғЎ бғҳбғ§бғ”бғңбғ”бғ‘бғ”бғң?","category":"travel-transport","level":"A2"},{"english":"exchange","georgian":"бғ’бғҗбғӘбғ•бғҡбғҗ","pronunciation":"/ЙӘksЛҲtКғeЙӘndК’/","example_en":"Where can I exchange money?","example_ka":"бғЎбғҗбғ“ бғЁбғ”бғӣбғҳбғ«бғҡбғҳбғҗ бғӨбғЈбғҡбғҳбғЎ бғ’бғҗбғӘбғ•бғҡбғҗ?","category":"travel-transport","level":"A2"},{"english":"customs","georgian":"бғЎбғҗбғ‘бғҗбғҹбғқ","pronunciation":"/ЛҲkКҢstЙҷmz/","example_en":"We passed through customs quickly.","example_ka":"бғЎбғҗбғ‘бғҗбғҹбғқбғЎ бғЎбғ¬бғ бғҗбғӨбғҗбғ“ бғ’бғҗбғ•бғҳбғҗбғ бғ”бғ—.","category":"travel-transport","level":"B1"},{"english":"border","georgian":"бғЎбғҗбғ–бғҰбғ•бғҗбғ бғҳ","pronunciation":"/ЛҲbЙ”ЛҗrdЙҷr/","example_en":"We crossed the border at noon.","example_ka":"бғЎбғҗбғ–бғҰбғ•бғҗбғ бғҳ бғЁбғЈбғҗбғ“бғҰбғҳбғЎбғҗбғЎ бғ’бғҗбғ“бғҗбғ•бғҷбғ•бғ”бғ—бғ”бғ—.","category":"travel-transport","level":"A2"},{"english":"abroad","georgian":"бғЎбғҗбғ–бғҰбғ•бғҗбғ бғ’бғҗбғ бғ”бғ—","pronunciation":"/ЙҷЛҲbrЙ”Лҗd/","example_en":"She studied abroad for two years.","example_ka":"бғҳбғЎ бғқбғ бғҳ бғ¬бғ”бғҡбғҳ бғЎбғҗбғ–бғҰбғ•бғҗбғ бғ’бғҗбғ бғ”бғ— бғЎбғ¬бғҗбғ•бғҡбғқбғ‘бғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"beach","georgian":"бғЎбғҗбғңбғҗбғһбғҳбғ бғқ","pronunciation":"/biЛҗtКғ/","example_en":"Let's go to the beach.","example_ka":"бғЎбғҗбғңбғҗбғһбғҳбғ бғқбғ–бғ” бғ¬бғҗбғ•бғҳбғ“бғ”бғ—.","category":"travel-transport","level":"A1"},{"english":"mountain","georgian":"бғӣбғ—бғҗ","pronunciation":"/ЛҲmaКҠntЙҷn/","example_en":"Georgia has beautiful mountains.","example_ka":"бғЎбғҗбғҘбғҗбғ бғ—бғ•бғ”бғҡбғқбғЁбғҳ бғҡбғҗбғӣбғҗбғ–бғҳ бғӣбғ—бғ”бғ‘бғҳбғҗ.","category":"travel-transport","level":"A1"},{"english":"sea","georgian":"бғ–бғҰбғ•бғҗ","pronunciation":"/siЛҗ/","example_en":"I love swimming in the sea.","example_ka":"бғ–бғҰбғ•бғҗбғЁбғҳ бғӘбғЈбғ бғ•бғҗ бғӣбғҳбғ§бғ•бғҗбғ бғЎ.","category":"travel-transport","level":"A1"},{"english":"lake","georgian":"бғўбғ‘бғҗ","pronunciation":"/leЙӘk/","example_en":"We camped by the lake.","example_ka":"бғўбғ‘бғҗбғЎбғ—бғҗбғң бғ“бғҗбғ•бғ‘бғҗбғңбғҗбғҷбғ“бғҳбғ—.","category":"travel-transport","level":"A1"},{"english":"museum","georgian":"бғӣбғЈбғ–бғ”бғЈбғӣбғҳ","pronunciation":"/mjuЛҗЛҲziЛҗЙҷm/","example_en":"Let's visit the museum tomorrow.","example_ka":"бғ®бғ•бғҗбғҡ бғӣбғЈбғ–бғ”бғЈбғӣбғЎ бғ•бғ”бғ¬бғ•бғҳбғқбғ—.","category":"travel-transport","level":"A1"},{"english":"church","georgian":"бғ”бғҷбғҡбғ”бғЎбғҳбғҗ","pronunciation":"/tКғЙңЛҗrtКғ/","example_en":"The old church is on the hill.","example_ka":"бғ«бғ•бғ”бғҡбғҳ бғ”бғҷбғҡбғ”бғЎбғҳбғҗ бғ‘бғқбғ бғӘбғ•бғ–бғ”бғҗ.","category":"travel-transport","level":"A1"},{"english":"castle","georgian":"бғӘбғҳбғ®бғ”бғЎбғҳбғӣбғҗбғ’бғ бғ”","pronunciation":"/ЛҲkГҰsЙҷl/","example_en":"We visited an ancient castle.","example_ka":"бғЈбғ«бғ•бғ”бғҡбғ”бғЎбғҳ бғӘбғҳбғ®бғ”бғЎбғҳбғӣбғҗбғ’бғ бғ” бғӣбғқбғ•бғҳбғңбғҗбғ®бғЈбғҡбғ”бғ—.","category":"travel-transport","level":"A2"},{"english":"downtown","georgian":"бғӘбғ”бғңбғўбғ бғҳ","pronunciation":"/ЛҲdaКҠntaКҠn/","example_en":"Let's walk to downtown.","example_ka":"бғӘбғ”бғңбғўбғ бғЁбғҳ бғ’бғҗбғ•бғҳбғЎбғ”бғҳбғ бғңбғқбғ—.","category":"travel-transport","level":"A2"},{"english":"delay","georgian":"бғ“бғҗбғ’бғ•бғҳбғҗбғңбғ”бғ‘бғҗ","pronunciation":"/dЙӘЛҲleЙӘ/","example_en":"There was a two-hour delay.","example_ka":"бғқбғ бғЎбғҗбғҗбғ—бғҳбғҗбғңбғҳ бғ“бғҗбғ’бғ•бғҳбғҗбғңбғ”бғ‘бғҗ бғҳбғ§бғқ.","category":"travel-transport","level":"A2"},{"english":"cancel","georgian":"бғ’бғҗбғЈбғҘбғӣбғ”бғ‘бғҗ","pronunciation":"/ЛҲkГҰnsЙҷl/","example_en":"The flight was canceled.","example_ka":"бғӨбғ бғ”бғңбғҗ бғ’бғҗбғЈбғҘбғӣбғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"platform","georgian":"бғһбғҡбғҗбғўбғӨбғқбғ бғӣбғҗ","pronunciation":"/ЛҲplГҰtfЙ”Лҗrm/","example_en":"The train leaves from platform three.","example_ka":"бғӣбғҗбғўбғҗбғ бғ”бғ‘бғ”бғҡбғҳ бғӣбғ”бғЎбғҗбғӣбғ” бғһбғҡбғҗбғўбғӨбғқбғ бғӣбғҳбғ“бғҗбғң бғӣбғҳбғ“бғҳбғЎ.","category":"travel-transport","level":"A2"},{"english":"schedule","georgian":"бғ’бғҗбғңбғ бғҳбғ’бғҳ","pronunciation":"/ЛҲskЙӣdК’uЛҗl/","example_en":"Check the bus schedule online.","example_ka":"бғҗбғ•бғўбғқбғ‘бғЈбғЎбғҳбғЎ бғ’бғҗбғңбғ бғҳбғ’бғҳ бғҳбғңбғўбғ”бғ бғңбғ”бғўбғЁбғҳ бғЁбғ”бғҗбғӣбғқбғ¬бғӣбғ”.","category":"travel-transport","level":"A2"},{"english":"backpack","georgian":"бғ–бғЈбғ бғ’бғ©бғҗбғңбғ—бғҗ","pronunciation":"/ЛҲbГҰkpГҰk/","example_en":"Put your backpack in the overhead compartment.","example_ka":"бғ–бғЈбғ бғ’бғ©бғҗбғңбғ—бғҗ бғ–бғ”бғ“бғҗ бғ—бғҗбғ бғқбғ–бғ” бғ“бғҗбғ“бғ”.","category":"travel-transport","level":"A1"},{"english":"sunglasses","georgian":"бғЎбғҗбғ—бғ•бғҗбғҡбғ”","pronunciation":"/ЛҲsКҢnЙЎlГҰsЙӘz/","example_en":"Don't forget your sunglasses.","example_ka":"бғЎбғҗбғ—бғ•бғҗбғҡбғ” бғҗбғ  бғ“бғҗбғ’бғҗбғ•бғҳбғ¬бғ§бғ“бғ”бғЎ.","category":"travel-transport","level":"A1"},{"english":"camera","georgian":"бғҷбғҗбғӣбғ”бғ бғҗ","pronunciation":"/ЛҲkГҰmЙҷrЙҷ/","example_en":"Bring your camera for the trip.","example_ka":"бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗбғЁбғҳ бғҷбғҗбғӣбғ”бғ бғҗ бғ¬бғҗбғҳбғҰбғ”.","category":"travel-transport","level":"A1"},{"english":"postcard","georgian":"бғЎбғҗбғӨбғқбғЎбғўбғқ бғ‘бғҗбғ бғҗбғ—бғҳ","pronunciation":"/ЛҲpoКҠstkЙ‘Лҗrd/","example_en":"I sent a postcard to my friend.","example_ka":"бғӣбғ”бғ’бғқбғ‘бғҗбғ бғЎ бғЎбғҗбғӨбғқбғЎбғўбғқ бғ‘бғҗбғ бғҗбғ—бғҳ бғ’бғҗбғ•бғЈбғ’бғ–бғҗбғ•бғңбғ”.","category":"travel-transport","level":"A1"},{"english":"embassy","georgian":"бғЎбғҗбғ”бғҡбғ©бғқ","pronunciation":"/ЛҲЙӣmbЙҷsi/","example_en":"Go to the embassy for your visa.","example_ka":"бғ•бғҳбғ–бғҳбғЎбғ—бғ•бғҳбғЎ бғЎбғҗбғ”бғҡбғ©бғқбғЁбғҳ бғ¬бғҗбғ“бғҳ.","category":"travel-transport","level":"B1"},{"english":"gate","georgian":"бғҷбғҗбғ бғҳбғ‘бғӯбғ”","pronunciation":"/ЙЎeЙӘt/","example_en":"Go to gate number five.","example_ka":"бғӣбғ”бғ®бғЈбғ—бғ” бғҷбғҗбғ бғҳбғ‘бғӯбғ”бғЎбғ—бғҗбғң бғ¬бғҗбғ“бғҳ.","category":"travel-transport","level":"A2"},{"english":"seat","georgian":"бғҗбғ“бғ’бғҳбғҡбғҳ","pronunciation":"/siЛҗt/","example_en":"Is this seat taken?","example_ka":"бғ”бғЎ бғҗбғ“бғ’бғҳбғҡбғҳ бғ“бғҗбғҷбғҗбғ•бғ”бғ‘бғЈбғҡбғҳбғҗ?","category":"travel-transport","level":"A1"},{"english":"driver","georgian":"бғӣбғ«бғҰбғқбғҡбғҳ","pronunciation":"/ЛҲdraЙӘvЙҷr/","example_en":"The taxi driver was very friendly.","example_ka":"бғўбғҗбғҘбғЎбғҳбғЎ бғӣбғ«бғҰбғқбғҡбғҳ бғ«бғҗбғҡбғҳбғҗбғң бғӣбғ”бғ’бғқбғ‘бғ бғЈбғҡбғҳ бғҳбғ§бғқ.","category":"travel-transport","level":"A1"},{"english":"passenger","georgian":"бғӣбғ’бғ–бғҗбғ•бғ бғҳ","pronunciation":"/ЛҲpГҰsЙҷndК’Йҷr/","example_en":"All passengers must fasten their seatbelts.","example_ka":"бғ§бғ•бғ”бғҡбғҗ бғӣбғ’бғ–бғҗбғ•бғ бғӣбғҗ бғҰбғ•бғ”бғ“бғҳ бғЈбғңбғ“бғҗ бғЁбғ”бғҳбғҷбғ бғҗбғЎ.","category":"travel-transport","level":"A2"},{"english":"pilot","georgian":"бғһбғҳбғҡбғқбғўбғҳ","pronunciation":"/ЛҲpaЙӘlЙҷt/","example_en":"The pilot announced the landing.","example_ka":"бғһбғҳбғҡбғқбғўбғӣбғҗ бғ“бғҗбғЁбғ•бғ”бғ‘бғҗ бғ’бғҗбғӣбғқбғҗбғӘбғ®бғҗбғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"landing","georgian":"бғ“бғҗбғЁбғ•бғ”бғ‘бғҗ","pronunciation":"/ЛҲlГҰndЙӘЕӢ/","example_en":"The landing was very smooth.","example_ka":"бғ“бғҗбғЁбғ•бғ”бғ‘бғҗ бғ«бғҗбғҡбғҳбғҗбғң бғ бғ‘бғҳбғҡбғҳ бғҳбғ§бғқ.","category":"travel-transport","level":"A2"},{"english":"takeoff","georgian":"бғҗбғӨбғ бғ”бғңбғҗ","pronunciation":"/ЛҲteЙӘkЙ”Лҗf/","example_en":"The takeoff was on time.","example_ka":"бғҗбғӨбғ бғ”бғңбғҗ бғ“бғ бғқбғ–бғ” бғҳбғ§бғқ.","category":"travel-transport","level":"A2"},{"english":"ferry","georgian":"бғ‘бғқбғ бғҗбғңбғҳ","pronunciation":"/ЛҲfЙӣri/","example_en":"We took a ferry across the river.","example_ka":"бғӣбғ“бғҳбғңбғҗбғ бғҳбғЎ бғ’бғҗбғ“бғҗбғЎбғҗбғҡбғҗбғ®бғҗбғ“ бғ‘бғқбғ бғҗбғңбғҳ бғҗбғ•бғҳбғҰбғ”бғ—.","category":"travel-transport","level":"A2"},{"english":"hostel","georgian":"бғ°бғқбғЎбғўбғ”бғҡбғҳ","pronunciation":"/ЛҲhЙ’stЙҷl/","example_en":"Hostels are cheaper than hotels.","example_ka":"бғ°бғқбғЎбғўбғ”бғҡбғ”бғ‘бғҳ бғЎбғҗбғЎбғўбғЈбғӣбғ бғқбғ”бғ‘бғ–бғ” бғҳбғҗбғӨбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"layover","georgian":"бғ’бғҗбғ“бғҗбғҜбғ“бғқбғӣбғҗ","pronunciation":"/ЛҲleЙӘЙҷКҠvЙҷr/","example_en":"We have a 4-hour layover in Istanbul.","example_ka":"бғЎбғўбғҗбғӣбғ‘бғЈбғҡбғЁбғҳ 4-бғЎбғҗбғҗбғ—бғҳбғҗбғңбғҳ бғ’бғҗбғ“бғҗбғҜбғ“бғқбғӣбғҗ бғ’бғ•бғҗбғҘбғ•бғЎ.","category":"travel-transport","level":"B1"},{"english":"delayed","georgian":"бғ“бғҗбғ’бғ•бғҳбғҗбғңбғ”бғ‘бғЈбғҡбғҳ","pronunciation":"/dЙӘЛҲleЙӘd/","example_en":"Our flight was delayed by 3 hours.","example_ka":"бғ©бғ•бғ”бғңбғҳ бғ бғ”бғҳбғЎбғҳ 3 бғЎбғҗбғҗбғ—бғҳбғ— бғ“бғҗбғ’бғ•бғҳбғҗбғңбғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"transfer","georgian":"бғўбғ бғҗбғңбғЎбғӨбғ”бғ бғҳ","pronunciation":"/ЛҲtrГҰnsfЙңЛҗr/","example_en":"The hotel offers free airport transfer.","example_ka":"бғЎбғҗбғЎбғўбғЈбғӣбғ бғқ бғЈбғӨбғҗбғЎбғқ бғҗбғ”бғ бғқбғһбғқбғ бғўбғҳбғЎ бғўбғ бғҗбғңбғЎбғӨбғ”бғ бғЎ бғ’бғ—бғҗбғ•бғҗбғ–бғқбғ‘бғ—.","category":"travel-transport","level":"A2"},{"english":"itinerary","georgian":"бғӣбғҗбғ бғЁбғ бғЈбғўбғҳ","pronunciation":"/aЙӘЛҲtЙӘnЙҷrЙҷri/","example_en":"What's our itinerary for tomorrow?","example_ka":"бғ®бғ•бғҗбғҡ бғ бғҗ бғӣбғҗбғ бғЁбғ бғЈбғўбғҳ бғ’бғ•бғҗбғҘбғ•бғЎ?","category":"travel-transport","level":"B1"},{"english":"tip","georgian":"бғ©бғҗбғҳбғЎ бғӨбғЈбғҡбғҳ","pronunciation":"/tЙӘp/","example_en":"In America, you should always leave a tip.","example_ka":"бғҗбғӣбғ”бғ бғҳбғҷбғҗбғЁбғҳ бғ§бғқбғ•бғ”бғҡбғ—бғ•бғҳбғЎ бғЈбғңбғ“бғҗ бғ“бғҗбғўбғқбғ•бғқ бғ©бғҗбғҳбғЎ бғӨбғЈбғҡбғҳ.","category":"travel-transport","level":"A2"},{"english":"local","georgian":"бғҗбғ“бғ’бғҳбғҡбғқбғ‘бғ бғҳбғ•бғҳ","pronunciation":"/ЛҲlЙҷКҠkЙҷl/","example_en":"Try the local food вҖ” it's always the best.","example_ka":"бғҗбғ“бғ’бғҳбғҡбғқбғ‘бғ бғҳбғ•бғҳ бғЎбғҗбғҷбғ•бғ”бғ‘бғҳ бғЎбғӘбғҗбғ“бғ” вҖ” бғ§бғқбғ•бғ”бғҡбғ—бғ•бғҳбғЎ бғЎбғҗбғЈбғҷбғ”бғ—бғ”бғЎбғқбғҗ.","category":"travel-transport","level":"A2"},{"english":"landmark","georgian":"бғҰбғҳбғ бғЁбғ”бғЎбғҗбғңбғҳбғЁбғңбғҗбғқбғ‘бғҗ","pronunciation":"/ЛҲlГҰndmЙ‘Лҗk/","example_en":"The Eiffel Tower is the most famous landmark in Paris.","example_ka":"бғ”бғҳбғӨбғ”бғҡбғҳбғЎ бғҷбғқбғЁбғҷбғҳ бғһбғҗбғ бғҳбғ–бғҳбғЎ бғ§бғ•бғ”бғҡбғҗбғ–бғ” бғӘбғңбғқбғ‘бғҳбғҡбғҳ бғҰбғҳбғ бғЁбғ”бғЎбғҗбғңбғҳбғЁбғңбғҗбғқбғ‘бғҗбғҗ.","category":"travel-transport","level":"B1"},{"english":"cruise","georgian":"бғҷбғ бғЈбғҳбғ–бғҳ","pronunciation":"/kruЛҗz/","example_en":"We went on a Mediterranean cruise.","example_ka":"бғ®бғӣбғ”бғҡбғ—бғҗбғЁбғЈбғҗ бғ–бғҰбғ•бғҳбғЎ бғҷбғ бғЈбғҳбғ–бғ–бғ” бғ¬бғҗбғ•бғ”бғ“бғҳбғ—.","category":"travel-transport","level":"B1"},{"english":"route","georgian":"бғӣбғҗбғ бғЁбғ бғЈбғўбғҳ","pronunciation":"/ruЛҗt/","example_en":"This route is faster during rush hour.","example_ka":"бғ”бғЎ бғӣбғҗбғ бғЁбғ бғЈбғўбғҳ бғЎбғҗбғӘбғқбғ‘бғҳбғЎ бғ“бғ бғқбғЎ бғЈбғӨбғ бғқ бғЎбғ¬бғ бғҗбғӨбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"destination","georgian":"бғ“бғҗбғңбғҳбғЁбғңбғЈбғҡбғ”бғ‘бғҳбғЎ бғҗбғ“бғ’бғҳбғҡбғҳ","pronunciation":"/ЛҢdestЙӘЛҲneЙӘКғЙҷn/","example_en":"What's your final destination?","example_ka":"бғ бғҗ бғҗбғ бғҳбғЎ бғ—бғҘбғ•бғ”бғңбғҳ бғЎбғҗбғ‘бғқбғҡбғқбғқ бғ“бғҗбғңбғҳбғЁбғңбғЈбғҡбғ”бғ‘бғҳбғЎ бғҗбғ“бғ’бғҳбғҡбғҳ?","category":"travel-transport","level":"B1"},{"english":"adventure","georgian":"бғ—бғҗбғ•бғ’бғҗбғ“бғҗбғЎбғҗбғ•бғҗбғҡбғҳ","pronunciation":"/ЙҷdЛҲventКғЙҷr/","example_en":"Traveling is always an adventure.","example_ka":"бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗ бғ§бғқбғ•бғ”бғҡбғ—бғ•бғҳбғЎ бғ—бғҗбғ•бғ’бғҗбғ“бғҗбғЎбғҗбғ•бғҗбғҡбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"exploration","georgian":"бғ“бғҗбғ—бғ•бғҗбғҡбғҳбғ”бғ бғ”бғ‘бғҗ","pronunciation":"/ЛҢeksplЙҷЛҲreЙӘКғЙҷn/","example_en":"The exploration of new places is exciting.","example_ka":"бғҗбғ®бғҗбғҡбғҳ бғҗбғ“бғ’бғҳбғҡбғ”бғ‘бғҳбғЎ бғ“бғҗбғ—бғ•бғҗбғҡбғҳбғ”бғ бғ”бғ‘бғҗ бғЎбғҗбғҳбғңбғўбғ”бғ бғ”бғЎбғқбғҗ.","category":"travel-transport","level":"B2"},{"english":"sightseeing","georgian":"бғҰбғҳбғ бғЁбғ”бғЎбғҗбғңбғҳбғЁбғңбғҗбғқбғ‘бғ”бғ‘бғҳбғЎ бғ“бғҗбғ—бғ•бғҗбғҡбғҳбғ”бғ бғ”бғ‘бғҗ","pronunciation":"/ЛҲsaЙӘtЛҢsiЛҗЙӘЕӢ/","example_en":"We spent the day sightseeing.","example_ka":"бғӣбғ—бғ”бғҡбғҳ бғ“бғҰбғ” бғҰбғҳбғ бғЁбғ”бғЎбғҗбғңбғҳбғЁбғңбғҗбғқбғ‘бғ”бғ‘бғҳбғЎ бғ“бғҗбғ—бғ•бғҗбғҡбғҳбғ”бғ бғ”бғ‘бғҗбғЎ бғӣбғқбғ•бғҗбғ®бғӣбғҗбғ бғ”бғ—.","category":"travel-transport","level":"A2"},{"english":"backpacking","georgian":"бғ–бғЈбғ бғ’бғ©бғҗбғңбғ—бғҳбғ— бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗ","pronunciation":"/ЛҲbГҰkpГҰkЙӘЕӢ/","example_en":"Backpacking through Europe is a great experience.","example_ka":"бғ”бғ•бғ бғқбғһбғҗбғЁбғҳ бғ–бғЈбғ бғ’бғ©бғҗбғңбғ—бғҳбғ— бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗ бғЁбғ”бғЎбғҗбғңбғҳбғЁбғңбғҗбғ•бғҳ бғ’бғҗбғӣбғқбғӘбғ“бғҳбғҡбғ”бғ‘бғҗбғҗ.","category":"travel-transport","level":"B1"},{"english":"accommodation","georgian":"бғ’бғҗбғңбғ—бғҗбғ•бғЎбғ”бғ‘бғҗ","pronunciation":"/ЙҷЛҢkЙ’mЙҷЛҲdeЙӘКғЙҷn/","example_en":"We need to find accommodation for tonight.","example_ka":"бғҰбғҗбғӣбғҳбғЎбғ—бғ•бғҳбғЎ бғ’бғҗбғңбғ—бғҗбғ•бғЎбғ”бғ‘бғҳбғЎ бғһбғқбғ•бғңбғҗ бғ’бғ•бғӯбғҳбғ бғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"B1"},{"english":"rental","georgian":"бғҳбғҜбғҗбғ бғҗ","pronunciation":"/ЛҲrentЙҷl/","example_en":"Car rental is available at the airport.","example_ka":"бғҗбғ”бғ бғқбғһбғқбғ бғўбғЁбғҳ бғҗбғ•бғўбғқбғӣбғқбғ‘бғҳбғҡбғҳбғЎ бғҳбғҜбғҗбғ бғҗ бғЁбғ”бғЎбғҗбғ«бғҡбғ”бғ‘бғ”бғҡбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"motorway","georgian":"бғӣбғҗбғ’бғҳбғЎбғўбғ бғҗбғҡбғҳ","pronunciation":"/ЛҲmЙҷКҠtЙҷweЙӘ/","example_en":"Take the motorway to save time.","example_ka":"бғ“бғ бғқбғҳбғЎ бғ“бғҗбғЎбғҗбғ–бғқбғ’бғҗбғ“ бғӣбғҗбғ’бғҳбғЎбғўбғ бғҗбғҡбғҳ бғҗбғҳбғ бғ©бғҳбғ”.","category":"travel-transport","level":"B1"},{"english":"junction","georgian":"бғҷбғ•бғ”бғ—бғҗ","pronunciation":"/ЛҲdК’КҢЕӢkКғЙҷn/","example_en":"Turn left at the next junction.","example_ka":"бғЁбғ”бғӣбғ“бғ”бғ’ бғҷбғ•бғ”бғ—бғҗбғ–бғ” бғӣбғҗбғ бғӘбғ®бғңбғҳбғ• бғӣбғқбғЈбғ®бғ•бғҳбғ”.","category":"travel-transport","level":"B1"},{"english":"tunnel","georgian":"бғ’бғ•бғҳбғ бғҗбғ‘бғҳ","pronunciation":"/ЛҲtКҢnЙҷl/","example_en":"The tunnel goes under the mountain.","example_ka":"бғ’бғ•бғҳбғ бғҗбғ‘бғҳ бғӣбғ—бғҳбғЎ бғҘбғ•бғ”бғЁ бғ’бғҗбғ“бғҳбғЎ.","category":"travel-transport","level":"A2"},{"english":"roundabout","georgian":"бғ¬бғ бғҳбғЈбғҡбғҳ бғ’бғ–бғҗбғҷбғ•бғ”бғ—бғҳ","pronunciation":"/ЛҲraКҠndЙҷbaКҠt/","example_en":"Take the second exit at the roundabout.","example_ka":"бғ¬бғ бғҳбғЈбғҡбғҳ бғ’бғ–бғҗбғҷбғ•бғ”бғ—бғҳбғ“бғҗбғң бғӣбғ”бғқбғ бғ” бғ’бғҗбғӣбғқбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғҳ бғҗбғҳбғ бғ©бғҳбғ”.","category":"travel-transport","level":"B1"},{"english":"pedestrian","georgian":"бғӨбғ”бғ®бғӣбғҗбғ•бғҗбғҡбғҳ","pronunciation":"/pЙҷЛҲdestriЙҷn/","example_en":"Use the pedestrian crossing.","example_ka":"бғӨбғ”бғ®бғӣбғҗбғ•бғҗбғҡбғ—бғҗ бғ’бғҗбғ“бғҗбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғҳ бғ’бғҗбғӣбғқбғҳбғ§бғ”бғңбғ”.","category":"travel-transport","level":"A2"},{"english":"crosswalk","georgian":"бғ’бғҗбғ“бғҗбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғҳ","pronunciation":"/ЛҲkrЙ’swЙ”Лҗk/","example_en":"Wait at the crosswalk for the light.","example_ka":"бғ’бғҗбғ“бғҗбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғ—бғҗбғң бғЁбғЈбғҘбғ–бғ” бғ“бғҗбғ”бғҡбғқбғ“бғ”.","category":"travel-transport","level":"A2"},{"english":"sidewalk","georgian":"бғўбғ бғқбғўбғЈбғҗбғ бғҳ","pronunciation":"/ЛҲsaЙӘdwЙ”Лҗk/","example_en":"Walk on the sidewalk, not the road.","example_ka":"бғўбғ бғқбғўбғЈбғҗбғ бғ–бғ” бғҳбғҗбғ бғ”, бғҗбғ бғҗ бғ’бғ–бғҗбғ–бғ”.","category":"travel-transport","level":"A1"},{"english":"highway","georgian":"бғЁбғўбғҗбғўбғ—бғҗбғЁбғқбғ бғҳбғЎбғқ бғ’бғ–бғҗ","pronunciation":"/ЛҲhaЙӘweЙӘ/","example_en":"The highway is congested during peak hours.","example_ka":"бғЁбғўбғҗбғўбғ—бғҗбғЁбғқбғ бғҳбғЎбғқ бғ’бғ–бғҗ бғһбғҳбғҷбғҳбғЎ бғЎбғҗбғҗбғ—бғ”бғ‘бғЁбғҳ бғ’бғҗбғ“бғҗбғ‘бғ”бғ бғҳбғҡбғҳбғҗ.","category":"travel-transport","level":"B1"},{"english":"lane","georgian":"бғ–бғқбғҡбғҳ","pronunciation":"/leЙӘn/","example_en":"Stay in the right lane.","example_ka":"бғӣбғҗбғ бғҜбғ•бғ”бғңбғҗ бғ–бғқбғҡбғЁбғҳ бғ“бғҗбғ бғ©бғҳ.","category":"travel-transport","level":"A2"},{"english":"overtake","georgian":"бғ’бғҗбғ“бғҗбғӯбғҗбғ бғ‘бғ”бғ‘бғҗ","pronunciation":"/ЛҢЙҷКҠvЙҷrЛҲteЙӘk/","example_en":"Do not overtake on curves.","example_ka":"бғӣбғқбғЎбғҗбғ®бғ•бғ”бғ•бғ”бғ‘бғЁбғҳ бғ’бғҗбғ“бғҗбғӯбғҗбғ бғ‘бғ”бғ‘бғҗ бғҗбғ  бғӣбғқбғҗбғ®бғ“бғҳбғңбғқ.","category":"travel-transport","level":"B1"},{"english":"accelerate","georgian":"бғҗбғ©бғҘбғҗбғ бғ”бғ‘бғҗ","pronunciation":"/ЙҷkЛҲselЙҷreЙӘt/","example_en":"Accelerate slowly on icy roads.","example_ka":"бғ§бғҳбғңбғЈбғҡбғқбғ•бғҗбғң бғ’бғ–бғ”бғ‘бғ–бғ” бғңбғ”бғҡбғҗ бғҗбғ©бғҘбғҗбғ бғ“бғҳ.","category":"travel-transport","level":"B1"},{"english":"brake","georgian":"бғ“бғҗбғӣбғЈбғ®бғ бғЈбғӯбғ”бғ‘бғҗ","pronunciation":"/breЙӘk/","example_en":"Apply the brake gently.","example_ka":"бғңбғҗбғ–бғҗбғ“ бғ’бғҗбғӣбғқбғҳбғ§бғ”бғңбғ” бғӣбғЈбғ®бғ бғЈбғӯбғҳ.","category":"travel-transport","level":"A2"},{"english":"fuel","georgian":"бғЎбғҗбғ¬бғ•бғҗбғ•бғҳ","pronunciation":"/ЛҲfjuЛҗЙҷl/","example_en":"We need to buy fuel for the car.","example_ka":"бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎбғ—бғ•бғҳбғЎ бғЎбғҗбғ¬бғ•бғҗбғ•бғҳбғЎ бғ§бғҳбғ“бғ•бғҗ бғ’бғ•бғӯбғҳбғ бғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"A2"},{"english":"gasoline","georgian":"бғ‘бғ”бғңбғ–бғҳбғңбғҳ","pronunciation":"/ЛҲЙЎГҰsЙҷliЛҗn/","example_en":"Fill the tank with gasoline.","example_ka":"бғ‘бғҗбғҷбғҳ бғ‘бғ”бғңбғ–бғҳбғңбғҳбғ— бғЁбғ”бғҗбғ•бғЎбғ”.","category":"travel-transport","level":"A2"},{"english":"diesel","georgian":"бғ“бғҳбғ–бғ”бғҡбғҳ","pronunciation":"/ЛҲdiЛҗzЙҷl/","example_en":"This truck runs on diesel.","example_ka":"бғ”бғЎ бғўбғ бғҗбғҷбғҳ бғ“бғҳбғ–бғ”бғҡбғ–бғ” бғӣбғЈбғЁбғҗбғқбғ‘бғЎ.","category":"travel-transport","level":"A2"},{"english":"mechanic","georgian":"бғӣбғ”бғҘбғҗбғңбғҳбғҷбғқбғЎбғҳ","pronunciation":"/mЙҷЛҲkГҰnЙӘk/","example_en":"The mechanic fixed my car.","example_ka":"бғӣбғ”бғҘбғҗбғңбғҳбғҷбғқбғЎбғӣбғҗ бғ©бғ”бғӣбғҳ бғӣбғҗбғңбғҘбғҗбғңбғҗ бғ’бғҗбғҗбғЎбғ¬бғқбғ бғҗ.","category":"travel-transport","level":"A2"},{"english":"engine","georgian":"бғ«бғ бғҗбғ•бғҗ","pronunciation":"/ЛҲendК’ЙӘn/","example_en":"The engine is making strange noises.","example_ka":"бғ«бғ бғҗбғ•бғҗ бғЈбғӘбғңбғҗбғЈбғ  бғ®бғӣбғ”бғ‘бғЎ бғ’бғҗбғӣбғқбғЎбғӘбғ”бғӣбғЎ.","category":"travel-transport","level":"A2"},{"english":"tire","georgian":"бғЎбғҗбғ‘бғЈбғ бғҗбғ•бғҳ","pronunciation":"/ЛҲtaЙӘЙҷr/","example_en":"I have a flat tire.","example_ka":"бғЎбғҗбғ‘бғЈбғ бғҗбғ•бғҳ бғ’бғҗбғӣбғ”бғҜбғҗбғ бғ“бғҗ.","category":"travel-transport","level":"A2"},{"english":"license","georgian":"бғӣбғқбғ¬бғӣбғқбғ‘бғҗ","pronunciation":"/ЛҲlaЙӘsЙҷns/","example_en":"Show me your driver's license.","example_ka":"бғӣбғ«бғҰбғқбғҡбғҳбғЎ бғӣбғқбғ¬бғӣбғқбғ‘бғҗ бғӣбғҗбғ©бғ•бғ”бғңбғ”.","category":"travel-transport","level":"A2"},{"english":"insurance","georgian":"бғ“бғҗбғ–бғҰбғ•бғ”бғ•бғҗ","pronunciation":"/ЙӘnЛҲКғКҠrЙҷns/","example_en":"Car insurance is mandatory.","example_ka":"бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғ“бғҗбғ–бғҰбғ•бғ”бғ•бғҗ бғЎбғҗбғ•бғҗбғҡбғ“бғ”бғ‘бғЈбғҡбғқбғҗ.","category":"travel-transport","level":"B1"},{"english":"registration","georgian":"бғ бғ”бғ’бғҳбғЎбғўбғ бғҗбғӘбғҳбғҗ","pronunciation":"/ЛҢredК’ЙӘЛҲstreЙӘКғЙҷn/","example_en":"Keep your car registration in the glove box.","example_ka":"бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғ бғ”бғ’бғҳбғЎбғўбғ бғҗбғӘбғҳбғҗ бғ®бғ”бғҡбғ—бғҗбғ—бғӣбғҗбғңбғЁбғҳ бғЁбғ”бғҳбғңбғҗбғ®бғ”.","category":"travel-transport","level":"B1"},{"english":"speedometer","georgian":"бғЎбғһбғҳбғ“бғқбғӣбғ”бғўбғ бғҳ","pronunciation":"/spiЛҲdЙ’mЙӘtЙҷr/","example_en":"The speedometer shows 80 km/h.","example_ka":"бғЎбғһбғҳбғ“бғқбғӣбғ”бғўбғ бғҳ 80 бғҷбғӣ/бғЎбғ—-бғЎ бғҗбғңбғҳбғЁбғңбғ”бғ‘бғЎ.","category":"travel-transport","level":"B1"},{"english":"navigation","georgian":"бғңбғҗбғ•бғҳбғ’бғҗбғӘбғҳбғҗ","pronunciation":"/ЛҢnГҰvЙӘЛҲЙЎeЙӘКғЙҷn/","example_en":"Use GPS navigation to find the way.","example_ka":"бғ’бғ–бғҳбғЎ бғЎбғҗбғһбғқбғ•бғңбғ”бғҡбғҗбғ“ GPS бғңбғҗбғ•бғҳбғ’бғҗбғӘбғҳбғҗ бғ’бғҗбғӣбғқбғҳбғ§бғ”бғңбғ”.","category":"travel-transport","level":"B1"},{"english":"compass","georgian":"бғҷбғқбғӣбғһбғҗбғЎбғҳ","pronunciation":"/ЛҲkКҢmpЙҷs/","example_en":"A compass helps you find direction.","example_ka":"бғҷбғқбғӣбғһбғҗбғЎбғҳ бғӣбғҳбғӣбғҗбғ бғ—бғЈбғҡбғ”бғ‘бғҳбғЎ бғ“бғҗбғ“бғ’бғ”бғңбғҗбғЁбғҳ бғ’бғ”бғ®бғӣбғҗбғ бғ”бғ‘бғҗ.","category":"travel-transport","level":"A2"},{"english":"mileage","georgian":"бғ’бғҗбғ•бғҡбғҳбғҡбғҳ бғӣбғҗбғңбғ«бғҳбғҡбғҳ","pronunciation":"/ЛҲmaЙӘlЙӘdК’/","example_en":"This car has low mileage.","example_ka":"бғҗбғӣ бғӣбғҗбғңбғҘбғҗбғңбғҗбғЎ бғӣбғӘбғҳбғ бғ” бғ’бғҗбғ•бғҡбғҳбғҡбғҳ бғӣбғҗбғңбғ«бғҳбғҡбғҳ бғҗбғҘбғ•бғЎ.","category":"travel-transport","level":"B1"},{"english":"odometer","georgian":"бғқбғ“бғқбғӣбғ”бғўбғ бғҳ","pronunciation":"/ЙҷКҠЛҲdЙ’mЙӘtЙҷr/","example_en":"The odometer shows 50,000 kilometers.","example_ka":"бғқбғ“бғқбғӣбғ”бғўбғ бғҳ 50,000 бғҷбғҳбғҡбғқбғӣбғ”бғўбғ бғЎ бғҗбғңбғҳбғЁбғңбғ”бғ‘бғЎ.","category":"travel-transport","level":"B2"},{"english":"clutch","georgian":"бғҷбғҡбғҗбғ©бғҳ","pronunciation":"/klКҢtКғ/","example_en":"Press the clutch before changing gears.","example_ka":"бғЎбғҗбғ©бғҘбғҗбғ бғқбғЎ бғЁбғ”бғӘбғ•бғҡбғҗбғӣбғ“бғ” бғҷбғҡбғҗбғ©бғҳ бғ“бғҗбғҗбғӯбғҳбғ бғ”.","category":"travel-transport","level":"B1"},{"english":"gear","georgian":"бғЎбғҗбғ©бғҘбғҗбғ бғқ","pronunciation":"/ЙЎЙӘЙҷr/","example_en":"Shift to second gear.","example_ka":"бғӣбғ”бғқбғ бғ” бғЎбғҗбғ©бғҘбғҗбғ бғқбғ–бғ” бғ’бғҗбғ“бғҗбғ•бғҳбғ“бғҳ.","category":"travel-transport","level":"A2"},{"english":"steering","georgian":"бғЎбғўбғҳбғ бғҳбғңбғ’бғҳ","pronunciation":"/ЛҲstЙӘЙҷrЙӘЕӢ/","example_en":"The steering wheel is on the left.","example_ka":"бғЎбғўбғҳбғ бғҳбғңбғ’бғҳбғЎ бғҰбғ”бғқ бғӣбғҗбғ бғӘбғ®бғ”бғңбғҗ бғӣбғ®бғҗбғ бғ”бғЎ бғҗбғ бғҳбғЎ.","category":"travel-transport","level":"A2"},{"english":"horn","georgian":"бғЎбғҳбғ’бғңбғҗбғҡбғҳ","pronunciation":"/hЙ”Лҗrn/","example_en":"Don't honk the horn unnecessarily.","example_ka":"бғЎбғҳбғ’бғңбғҗбғҡбғҳ бғЈбғЎбғҗбғӨбғЈбғ«бғ•бғҡбғқбғ“ бғҗбғ  бғҳбғ®бғӣбғҗбғ бғ”.","category":"travel-transport","level":"A2"},{"english":"mirror","georgian":"бғЎбғҗбғ бғҷбғ”","pronunciation":"/ЛҲmЙӘrЙҷr/","example_en":"Check the rearview mirror.","example_ka":"бғЈбғҷбғҗбғңбғҗ бғЎбғҗбғ бғҷбғ” бғЁбғ”бғҗбғӣбғқбғ¬бғӣбғ”.","category":"travel-transport","level":"A2"},{"english":"windshield","georgian":"бғҘбғҗбғ бғЎбғҗбғӘбғҗбғ•бғҳ","pronunciation":"/ЛҲwЙӘndКғiЛҗld/","example_en":"The windshield is cracked.","example_ka":"бғҘбғҗбғ бғЎбғҗбғӘбғҗбғ•бғҳ бғңбғҗбғһбғЈбғҷбғ•бғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"headlight","georgian":"бғӨбғҗбғ бғҳ","pronunciation":"/ЛҲhedlaЙӘt/","example_en":"Turn on the headlights at night.","example_ka":"бғҰбғҗбғӣбғҳбғ— бғӨбғҗбғ бғ”бғ‘бғҳ бғ©бғҗбғ бғ—бғ”.","category":"travel-transport","level":"A2"},{"english":"indicator","georgian":"бғҳбғңбғ“бғҳбғҷбғҗбғўбғқбғ бғҳ","pronunciation":"/ЛҲЙӘndЙӘkeЙӘtЙҷr/","example_en":"Use the indicator before turning.","example_ka":"бғЁбғ”бғ‘бғ бғЈбғңбғ”бғ‘бғҗбғӣбғ“бғ” бғҳбғңбғ“бғҳбғҷбғҗбғўбғқбғ бғҳ бғ’бғҗбғӣбғқбғҳбғ§бғ”бғңбғ”.","category":"travel-transport","level":"A2"},{"english":"seatbelt","georgian":"бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ”бғ‘бғҳбғЎ бғҰбғ•бғ”бғ“бғҳ","pronunciation":"/ЛҲsiЛҗtbelt/","example_en":"Always fasten your seatbelt.","example_ka":"бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ”бғ‘бғҳбғЎ бғҰбғ•бғ”бғ“бғҳ бғ§бғқбғ•бғ”бғҡбғ—бғ•бғҳбғЎ бғЁбғ”бғҳбғҷбғҗбғ бғҳ.","category":"travel-transport","level":"A1"},{"english":"airbag","georgian":"бғ°бғҗбғ”бғ бғҳбғЎ бғ‘бғҗбғҡбғҳбғЁбғҳ","pronunciation":"/ЛҲeЙҷrbГҰЙЎ/","example_en":"The airbag deployed during the accident.","example_ka":"бғҗбғ•бғҗбғ бғҳбғҳбғЎбғҗбғЎ бғ°бғҗбғ”бғ бғҳбғЎ бғ‘бғҗбғҡбғҳбғЁбғҳ бғ’бғҗбғҳбғЁбғҗбғҡбғҗ.","category":"travel-transport","level":"B1"},{"english":"highway","georgian":"бғӣбғҗбғ’бғҳбғЎбғўбғ бғҗбғҡбғЈбғ бғҳ бғ’бғ–бғҗ","pronunciation":"/ЛҲhaЙӘweЙӘ/","example_en":"This highway connects major cities.","example_ka":"бғ”бғЎ бғӣбғҗбғ’бғҳбғЎбғўбғ бғҗбғҡбғЈбғ бғҳ бғ’бғ–бғҗ бғӣбғ—бғҗбғ•бғҗбғ  бғҘбғҗбғҡбғҗбғҘбғ”бғ‘бғЎ бғҗбғҷбғҗбғ•бғЁбғҳбғ бғ”бғ‘бғЎ.","category":"travel-transport","level":"B1"},{"english":"toll","georgian":"бғ’бғҗбғ“бғҗбғЎбғҗбғ®бғҗбғ“бғҳ","pronunciation":"/toКҠl/","example_en":"You must pay a toll to use this bridge.","example_ka":"бғҗбғӣ бғ®бғҳбғ“бғҳбғЎ бғ’бғҗбғӣбғқбғЎбғҗбғ§бғ”бғңбғ”бғ‘бғҡбғҗбғ“ бғ’бғҗбғ“бғҗбғЎбғҗбғ®бғҗбғ“бғҳ бғЈбғңбғ“бғҗ бғ’бғҗбғ“бғҗбғҳбғ®бғҗбғ“бғқ.","category":"travel-transport","level":"B1"},{"english":"detour","georgian":"бғ’бғ•бғ”бғ бғ“бғҳбғЎ бғҗбғ•бғҡбғ”бғ‘бғҗ","pronunciation":"/ЛҲdiЛҗtКҠr/","example_en":"Take a detour due to road construction.","example_ka":"бғ’бғ–бғҳбғЎ бғӣбғЁбғ”бғңбғ”бғ‘бғҡбғқбғ‘бғҳбғЎ бғ’бғҗбғӣбғқ бғ’бғ•бғ”бғ бғ“бғҳ бғҗбғ•бғҡбғҳбғ”.","category":"travel-transport","level":"B1"},{"english":"hitchhike","georgian":"бғӣбғқбғЎбғҗбғ’бғ бғ” бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғҡбғқбғ“бғҳбғңбғҳ","pronunciation":"/ЛҲhЙӘtКғhaЙӘk/","example_en":"It's not safe to hitchhike alone.","example_ka":"бғӣбғҗбғ бғўбғқ бғӣбғқбғЎбғҗбғ’бғ бғ” бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғҡбғқбғ“бғҳбғңбғҳ бғЎбғҗбғЁбғҳбғЁбғҳбғҗ.","category":"travel-transport","level":"B2"},{"english":"carpool","georgian":"бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғ—бғҗбғңбғҗбғ–бғҳбғҗбғ бғ”бғ‘бғҗ","pronunciation":"/ЛҲkЙ‘ЛҗrpuЛҗl/","example_en":"We carpool to work to save money.","example_ka":"бғӨбғЈбғҡбғҳбғЎ бғ“бғҗбғ–бғқбғ’бғ•бғҳбғЎбғ—бғ•бғҳбғЎ бғЎбғҗбғӣбғЎбғҗбғ®бғЈбғ бғЁбғҳ бғӣбғҗбғңбғҘбғҗбғңбғҳбғ— бғ”бғ бғ—бғҗбғ“ бғӣбғҳбғ•бғ“бғҳбғ•бғҗбғ бғ—.","category":"travel-transport","level":"B1"},{"english":"escalator","georgian":"бғ”бғЎбғҷбғҗбғҡбғҗбғўбғқбғ бғҳ","pronunciation":"/ЛҲeskЙҷleЙӘtЙҷr/","example_en":"Take the escalator to the second floor.","example_ka":"бғӣбғ”бғқбғ бғ” бғЎбғҗбғ бғ—бғЈбғҡбғ–бғ” бғ”бғЎбғҷбғҗбғҡбғҗбғўбғқбғ бғҳбғ— бғҗбғ•бғҳбғ“бғҳ.","category":"travel-transport","level":"A2"},{"english":"elevator","georgian":"бғҡбғҳбғӨбғўбғҳ","pronunciation":"/ЛҲelЙҷveЙӘtЙҷr/","example_en":"The elevator is out of order.","example_ka":"бғҡбғҳбғӨбғўбғҳ бғ’бғҗбғӨбғЈбғӯбғ”бғ‘бғЈбғҡбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"departure","georgian":"бғ’бғҗбғЁбғ•бғ”бғ‘бғҗ","pronunciation":"/dЙӘЛҲpЙ‘ЛҗrtКғЙҷr/","example_en":"Check the departure board for your flight.","example_ka":"бғӨбғ бғ”бғңбғҳбғЎ бғӣбғҗбғ©бғ•бғ”бғңбғ”бғ‘бғ”бғҡ бғӨбғҗбғӨбғҗбғ бғ–бғ” бғ’бғҗбғЁбғ•бғ”бғ‘бғҳбғЎ бғ“бғ бғқ бғЁбғ”бғҗбғӣбғқбғ¬бғӣбғ”.","category":"travel-transport","level":"A2"},{"english":"terminal","georgian":"бғўбғ”бғ бғӣбғҳбғңбғҗбғҡбғҳ","pronunciation":"/ЛҲtЙңЛҗrmЙӘnЙҷl/","example_en":"Which terminal does your flight leave from?","example_ka":"бғ бғқбғӣбғ”бғҡбғҳ бғўбғ”бғ бғӣбғҳбғңбғҗбғҡбғҳбғ“бғҗбғң бғӣбғҳбғ“бғҳбғЎ бғЁбғ”бғңбғҳ бғӨбғ бғ”бғңбғҗ?","category":"travel-transport","level":"A2"},{"english":"runway","georgian":"бғҗбғЎбғҗбғӨбғ бғ”бғңбғҳ бғ‘бғҳбғҡбғҳбғҷбғҳ","pronunciation":"/ЛҲrКҢnweЙӘ/","example_en":"The plane is taxiing to the runway.","example_ka":"бғ—бғ•бғҳбғ—бғӣбғӨбғ бғҳбғңбғҗбғ•бғҳ бғҗбғЎбғҗбғӨбғ бғ”бғңбғҳ бғ‘бғҳбғҡбғҳбғҷбғҳбғЎбғҷбғ”бғң бғӣбғҳбғ”бғӣбғҗбғ бғ—бғ”бғ‘бғҗ.","category":"travel-transport","level":"B1"},{"english":"cockpit","georgian":"бғҷбғҗбғ‘бғҳбғңбғҗ","pronunciation":"/ЛҲkЙ’kpЙӘt/","example_en":"The pilot sits in the cockpit.","example_ka":"бғһбғҳбғҡбғқбғўбғҳ бғҷбғҗбғ‘бғҳбғңбғҗбғЁбғҳ бғ–бғҳбғЎ.","category":"travel-transport","level":"B1"},{"english":"cabin","georgian":"бғЎбғҗбғӣбғ’бғ–бғҗбғ•бғ бғқ бғ“бғҗбғ бғ‘бғҗбғ–бғҳ","pronunciation":"/ЛҲkГҰbЙӘn/","example_en":"Please remain seated in the cabin.","example_ka":"бғ’бғ—бғ®бғқбғ•бғ—, бғЎбғҗбғӣбғ’бғ–бғҗбғ•бғ бғқ бғ“бғҗбғ бғ‘бғҗбғ–бғЁбғҳ бғӣбғҜбғ“бғқбғӣбғҗбғ бғ” бғ“бғҗбғ бғ©бғҳбғ—.","category":"travel-transport","level":"A2"},{"english":"aisle","georgian":"бғ’бғҗбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғҳ","pronunciation":"/aЙӘl/","example_en":"I prefer an aisle seat on long flights.","example_ka":"бғ’бғ бғ«бғ”бғҡ бғӨбғ бғ”бғңбғ”бғ‘бғ–бғ” бғ’бғҗбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғ—бғҗбғң бғҗбғ“бғ’бғҳбғҡбғҳ бғӣбғҳбғ бғ©бғ”бғ•бғңбғҳбғҗ.","category":"travel-transport","level":"B1"},{"english":"window","georgian":"бғӨбғҗбғңбғҜбғҗбғ бғҗ","pronunciation":"/ЛҲwЙӘndoКҠ/","example_en":"I want a window seat.","example_ka":"бғӨбғҗбғңбғҜбғ бғҳбғЎбғһбғҳбғ бғҗ бғҗбғ“бғ’бғҳбғҡбғҳ бғӣбғҳбғңбғ“бғҗ.","category":"travel-transport","level":"A1"},{"english":"turbulence","georgian":"бғўбғЈбғ бғ‘бғЈбғҡбғ”бғңбғўбғқбғ‘бғҗ","pronunciation":"/ЛҲtЙңЛҗrbjЙҷlЙҷns/","example_en":"We experienced some turbulence during the flight.","example_ka":"бғӨбғ бғ”бғңбғҳбғЎ бғ“бғ бғқбғЎ бғўбғЈбғ бғ‘бғЈбғҡбғ”бғңбғўбғқбғ‘бғҗ бғҳбғ§бғқ.","category":"travel-transport","level":"B2"},{"english":"altitude","georgian":"бғЎбғҳбғӣбғҗбғҰбғҡбғ”","pronunciation":"/ЛҲГҰltЙӘtuЛҗd/","example_en":"The plane is flying at high altitude.","example_ka":"бғ—бғ•бғҳбғ—бғӣбғӨбғ бғҳбғңбғҗбғ•бғҳ бғӣбғҗбғҰбғҗбғҡ бғЎбғҳбғӣбғҗбғҰбғҡбғ”бғ–бғ” бғ“бғҗбғӨбғ бғҳбғңбғҗбғ•бғЎ.","category":"travel-transport","level":"B2"},{"english":"checkpoint","georgian":"бғЎбғҗбғҷбғқбғңбғўбғ бғқбғҡбғқ бғһбғЈбғңбғҘбғўбғҳ","pronunciation":"/ЛҲtКғekpЙ”ЙӘnt/","example_en":"Pass through the security checkpoint.","example_ka":"бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ”бғ‘бғҳбғЎ бғЎбғҗбғҷбғқбғңбғўбғ бғқбғҡбғқ бғһбғЈбғңбғҘбғўбғҳ бғ’бғҗбғҳбғҗбғ бғ”.","category":"travel-transport","level":"B1"},{"english":"security","georgian":"бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ”бғ‘бғҗ","pronunciation":"/sЙӘЛҲkjКҠrЙҷti/","example_en":"Airport security is very strict.","example_ka":"бғҗбғ”бғ бғқбғһбғқбғ бғўбғҳбғЎ бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ”бғ‘бғҗ бғ«бғҗбғҡбғҳбғҗбғң бғӣбғҷбғҗбғӘбғ бғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"boarding","georgian":"бғ©бғҗбғҜбғ“бғқбғӣбғҗ","pronunciation":"/ЛҲbЙ”ЛҗrdЙӘЕӢ/","example_en":"Boarding will begin in 20 minutes.","example_ka":"бғ©бғҗбғҜбғ“бғқбғӣбғҗ 20 бғ¬бғЈбғ—бғЁбғҳ бғ“бғҗбғҳбғ¬бғ§бғ”бғ‘бғҗ.","category":"travel-transport","level":"A2"},{"english":"announcement","georgian":"бғ’бғҗбғңбғӘбғ®бғҗбғ“бғ”бғ‘бғҗ","pronunciation":"/ЙҷЛҲnaКҠnsmЙҷnt/","example_en":"Listen to the announcements carefully.","example_ka":"бғ’бғҗбғңбғӘбғ®бғҗбғ“бғ”бғ‘бғ”бғ‘бғЎ бғ§бғЈбғ бғҗбғ“бғҰбғ”бғ‘бғҳбғ— бғЈбғЎбғӣбғҳбғңбғ”.","category":"travel-transport","level":"A2"},{"english":"connecting","georgian":"бғ’бғҗбғ“бғҗбғӣбғ§бғ•бғҗбғңбғҳ","pronunciation":"/kЙҷЛҲnektЙӘЕӢ/","example_en":"I missed my connecting flight.","example_ka":"бғ’бғҗбғ“бғҗбғӣбғ§бғ•бғҗбғңбғҳ бғ бғ”бғҳбғЎбғҳ бғ’бғҗбғӣбғ•бғ бғ©бғҳ.","category":"travel-transport","level":"B1"},{"english":"trolley","georgian":"бғЈбғ бғҳбғҷбғҗ","pronunciation":"/ЛҲtrЙ’li/","example_en":"Use a trolley for heavy luggage.","example_ka":"бғӣбғ«бғҳбғӣбғ” бғ‘бғҗбғ бғ’бғҳбғЎбғ—бғ•бғҳбғЎ бғЈбғ бғҳбғҷбғҗ бғ’бғҗбғӣбғқбғҳбғ§бғ”бғңбғ”.","category":"travel-transport","level":"A2"},{"english":"carousel","georgian":"бғ‘бғҗбғ бғ’бғҳбғЎ бғҗбғҰбғ”бғ‘бғҳбғЎ бғҜбғҗбғӯбғ•бғЈбғ бғҳ","pronunciation":"/ЛҢkГҰrЙҷЛҲsel/","example_en":"Collect your luggage from carousel 3.","example_ka":"бғ‘бғҗбғ бғ’бғҳ бғӣбғ”-3 бғҜбғҗбғӯбғ•бғЈбғ бғҳбғ“бғҗбғң бғҗбғҳбғҰбғ”.","category":"travel-transport","level":"B1"},{"english":"conveyor","georgian":"бғҷбғқбғңбғ•бғ”бғҳбғ”бғ бғҳ","pronunciation":"/kЙҷnЛҲveЙӘЙҷr/","example_en":"Put your bag on the conveyor belt.","example_ka":"бғ©бғҗбғңбғ—бғҗ бғҷбғқбғңбғ•бғ”бғҳбғ”бғ бғ–бғ” бғ“бғҗбғ“бғ”.","category":"travel-transport","level":"B1"},{"english":"priority","georgian":"бғЈбғһбғҳбғ бғҗбғўбғ”бғЎбғқбғ‘бғҗ","pronunciation":"/praЙӘЛҲЙ”ЛҗrЙҷti/","example_en":"Business class has priority boarding.","example_ka":"бғ‘бғҳбғ–бғңбғ”бғЎ бғҷбғҡбғҗбғЎбғЎ бғ©бғҗбғҜбғ“бғқбғӣбғҳбғЎ бғЈбғһбғҳбғ бғҗбғўбғ”бғЎбғқбғ‘бғҗ бғҗбғҘбғ•бғЎ.","category":"travel-transport","level":"B1"},{"english":"economy","georgian":"бғ”бғҷбғқбғңбғқбғӣ бғҷбғҡбғҗбғЎбғҳ","pronunciation":"/ЙӘЛҲkЙ’nЙҷmi/","example_en":"Economy class tickets are cheaper.","example_ka":"бғ”бғҷбғқбғңбғқбғӣ бғҷбғҡбғҗбғЎбғҳбғЎ бғ‘бғҳбғҡбғ”бғ—бғ”бғ‘бғҳ бғЈбғӨбғ бғқ бғҳбғҗбғӨбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"business","georgian":"бғ‘бғҳбғ–бғңбғ”бғЎ бғҷбғҡбғҗбғЎбғҳ","pronunciation":"/ЛҲbЙӘznЙҷs/","example_en":"Business class offers more legroom.","example_ka":"бғ‘бғҳбғ–бғңбғ”бғЎ бғҷбғҡбғҗбғЎбғҳ бғӣбғ”бғў бғЎбғҳбғ•бғ бғӘбғ”бғЎ бғ’бғ—бғҗбғ•бғҗбғ–бғқбғ‘бғ—.","category":"travel-transport","level":"A2"},{"english":"upgrade","georgian":"бғ’бғҗбғңбғҗбғ®бғҡбғ”бғ‘бғҗ","pronunciation":"/ЛҲКҢpЙЎreЙӘd/","example_en":"Can I upgrade to business class?","example_ka":"бғ‘бғҳбғ–бғңбғ”бғЎ бғҷбғҡбғҗбғЎбғ–бғ” бғ’бғҗбғңбғҗбғ®бғҡбғ”бғ‘бғҗ бғЁбғ”бғӣбғҳбғ«бғҡбғҳбғҗ?","category":"travel-transport","level":"B1"},{"english":"refund","georgian":"бғ“бғҗбғ‘бғ бғЈбғңбғ”бғ‘бғҗ","pronunciation":"/ЛҲriЛҗfКҢnd/","example_en":"Can I get a refund for my ticket?","example_ka":"бғ‘бғҳбғҡбғ”бғ—бғҳбғЎ бғҰбғҳбғ бғ”бғ‘бғЈбғҡбғ”бғ‘бғҳбғЎ бғ“бғҗбғ‘бғ бғЈбғңбғ”бғ‘бғҗ бғЁбғ”бғӣбғҳбғ«бғҡбғҳбғҗ?","category":"travel-transport","level":"B1"},{"english":"voucher","georgian":"бғ•бғҗбғЈбғ©бғ”бғ бғҳ","pronunciation":"/ЛҲvaКҠtКғЙҷr/","example_en":"They gave us a meal voucher for the delay.","example_ka":"бғ“бғҗбғ’бғ•бғҳбғҗбғңбғ”бғ‘бғҳбғЎ бғ’бғҗбғӣбғқ бғЎбғҗбғҷбғ•бғ”бғ‘бғҳбғЎ бғ•бғҗбғЈбғ©бғ”бғ бғҳ бғӣбғқбғ’бғ•бғӘбғ”бғЎ.","category":"travel-transport","level":"B1"},{"english":"compensation","georgian":"бғҷбғқбғӣбғһбғ”бғңбғЎбғҗбғӘбғҳбғҗ","pronunciation":"/ЛҢkЙ’mpЙҷnЛҲseЙӘКғЙҷn/","example_en":"Passengers received compensation for the cancelled flight.","example_ka":"бғӣбғ’бғ–бғҗбғ•бғ бғ”бғ‘бғӣбғҗ бғ’бғҗбғЈбғҘбғӣбғ”бғ‘бғЈбғҡбғҳ бғ бғ”бғҳбғЎбғҳбғЎбғ—бғ•бғҳбғЎ бғҷбғқбғӣбғһбғ”бғңбғЎбғҗбғӘбғҳбғҗ бғӣбғҳбғҳбғҰбғ”бғЎ.","category":"travel-transport","level":"B2"},{"english":"oversold","georgian":"бғӣбғ”бғўбғҳбғЎбғӣбғ”бғўбғҗбғ“ бғ’бғҗбғ§бғҳбғ“бғЈбғҡбғҳ","pronunciation":"/ЛҢЙҷКҠvЙҷrЛҲsЙҷКҠld/","example_en":"The flight was oversold.","example_ka":"бғ бғ”бғҳбғЎбғҳ бғӣбғ”бғўбғҳбғЎбғӣбғ”бғўбғҗбғ“ бғ’бғҗбғ§бғҳбғ“бғЈбғҡбғҳ бғҳбғ§бғқ.","category":"travel-transport","level":"B2"},{"english":"standby","georgian":"бғӣбғқбғҡбғқбғ“бғҳбғңбғҳбғЎ бғ бғ”бғҹбғҳбғӣбғҳ","pronunciation":"/ЛҲstГҰndbaЙӘ/","example_en":"I'm on standby for the next flight.","example_ka":"бғЁбғ”бғӣбғ“бғ”бғ’бғҳ бғ бғ”бғҳбғЎбғҳбғЎбғ—бғ•бғҳбғЎ бғӣбғқбғҡбғқбғ“бғҳбғңбғҳбғЎ бғ бғ”бғҹбғҳбғӣбғЁбғҳ бғ•бғҗбғ .","category":"travel-transport","level":"B2"},{"english":"charter","georgian":"бғ©бғҗбғ бғўбғ”бғ бғЈбғҡбғҳ","pronunciation":"/ЛҲtКғЙ‘ЛҗrtЙҷr/","example_en":"We booked a charter flight to Greece.","example_ka":"бғЎбғҗбғ‘бғ”бғ бғ«бғңбғ”бғ—бғЁбғҳ бғ©бғҗбғ бғўбғ”бғ бғЈбғҡбғҳ бғ бғ”бғҳбғЎбғҳ бғ“бғҗбғ•бғҜбғҗбғ•бғЁбғңбғ”бғ—.","category":"travel-transport","level":"B2"},{"english":"domestic","georgian":"бғЁбғҳбғ“бғҗ","pronunciation":"/dЙҷЛҲmestЙӘk/","example_en":"This is a domestic flight within Georgia.","example_ka":"бғ”бғЎ бғЎбғҗбғҘбғҗбғ бғ—бғ•бғ”бғҡбғқбғЎ бғЁбғҳбғ“бғҗ бғ бғ”бғҳбғЎбғҳбғҗ.","category":"travel-transport","level":"B1"},{"english":"international","georgian":"бғЎбғҗбғ”бғ бғ—бғҗбғЁбғқбғ бғҳбғЎбғқ","pronunciation":"/ЛҢЙӘntЙҷrЛҲnГҰКғЙҷnЙҷl/","example_en":"International flights require a passport.","example_ka":"бғЎбғҗбғ”бғ бғ—бғҗбғЁбғқбғ бғҳбғЎбғқ бғ бғ”бғҳбғЎбғ”бғ‘бғҳбғЎбғ—бғ•бғҳбғЎ бғһбғҗбғЎбғһбғқбғ бғўбғҳ бғ”бғЎбғҗбғӯбғҳбғ бғқбғ”бғ‘бғҗ.","category":"travel-transport","level":"A2"},{"english":"baggage","georgian":"бғ‘бғҗбғ бғ’бғҳ","pronunciation":"/ЛҲbГҰЙЎЙӘdК’/","example_en":"Check your baggage at the counter.","example_ka":"бғ‘бғҗбғ бғ’бғҳ бғҰбғ бғҳбғҗбғҡбғ–бғ” бғ’бғҗбғ“бғҗбғҗбғ‘бғҗбғ бғ”.","category":"travel-transport","level":"A2"},{"english":"excess","georgian":"бғ–бғ”бғ“бғӣбғ”бғўбғҳ","pronunciation":"/ЙӘkЛҲses/","example_en":"You'll pay extra for excess baggage.","example_ka":"бғ–бғ”бғ“бғӣбғ”бғўбғҳ бғ‘бғҗбғ бғ’бғҳбғЎбғ—бғ•бғҳбғЎ бғ“бғҗбғӣбғҗбғўбғ”бғ‘бғҳбғ— бғ’бғҗбғ“бғҗбғҳбғ®бғ“бғҳ.","category":"travel-transport","level":"B1"},{"english":"allowance","georgian":"бғңбғқбғ бғӣбғҗ","pronunciation":"/ЙҷЛҲlaКҠЙҷns/","example_en":"What's the baggage allowance for this flight?","example_ka":"бғ бғҗ бғҗбғ бғҳбғЎ бғҗбғӣ бғ бғ”бғҳбғЎбғҳбғЎ бғ‘бғҗбғ бғ’бғҳбғЎ бғңбғқбғ бғӣбғҗ?","category":"travel-transport","level":"B1"},{"english":"prohibited","georgian":"бғҗбғҷбғ бғ«бғҗбғҡбғЈбғҡбғҳ","pronunciation":"/prЙҷЛҲhЙӘbЙӘtЙӘd/","example_en":"Liquids are prohibited in carry-on bags.","example_ka":"бғ®бғ”бғҡ бғ‘бғҗбғ бғ’бғЁбғҳ бғЎбғҳбғ—бғ®бғ”бғ”бғ‘бғҳ бғҗбғҷбғ бғ«бғҗбғҡбғЈбғҡбғҳбғҗ.","category":"travel-transport","level":"B2"},{"english":"declare","georgian":"бғ’бғҗбғӣбғқбғӘбғ®бғҗбғ“бғ”бғ‘бғҗ","pronunciation":"/dЙӘЛҲkler/","example_en":"You must declare valuable items at customs.","example_ka":"бғҰбғҳбғ бғ”бғ‘бғЈбғҡбғҳ бғңбғҳбғ•бғ—бғ”бғ‘бғҳ бғЎбғҗбғ‘бғҗбғҹбғқбғЁбғҳ бғЈбғңбғ“бғҗ бғ’бғҗбғӣбғқбғҗбғӘбғ®бғҗбғ“бғқ.","category":"travel-transport","level":"B1"},{"english":"duty-free","georgian":"бғЈбғ‘бғҗбғҹбғқ","pronunciation":"/ЛҢduЛҗti ЛҲfriЛҗ/","example_en":"I bought perfume at the duty-free shop.","example_ka":"бғЈбғ‘бғҗбғҹбғқ бғӣбғҗбғҰбғҗбғ–бғҳбғҗбғЁбғҳ бғЎбғЈбғңбғҗбғӣбғқ бғ•бғҳбғ§бғҳбғ“бғ”.","category":"travel-transport","level":"B1"},{"english":"quarantine","georgian":"бғҷбғҗбғ бғҗбғңбғўбғҳбғңбғҳ","pronunciation":"/ЛҲkwЙ”ЛҗrЙҷntiЛҗn/","example_en":"Travelers must quarantine for 14 days.","example_ka":"бғӣбғқбғ’бғ–бғҗбғЈбғ бғ”бғ‘бғҳ 14 бғ“бғҰбғҳбғ— бғҷбғҗбғ бғҗбғңбғўбғҳбғңбғЁбғҳ бғЈбғңбғ“бғҗ бғ“бғҗбғ бғ©бғңбғ”бғң.","category":"travel-transport","level":"B2"},{"english":"transit","georgian":"бғўбғ бғҗбғңбғ–бғҳбғўбғҳ","pronunciation":"/ЛҲtrГҰnzЙӘt/","example_en":"Passengers in transit don't need visas.","example_ka":"бғўбғ бғҗбғңбғ–бғҳбғўбғЈбғҡ бғӣбғ’бғ–бғҗбғ•бғ бғ”бғ‘бғЎ бғ•бғҳбғ–бғҗ бғҗбғ  бғЎбғӯбғҳбғ бғ“бғ”бғ‘бғҗбғ—.","category":"travel-transport","level":"B1"},{"english":"stopover","georgian":"бғ’бғҗбғ©бғ”бғ бғ”бғ‘бғҗ","pronunciation":"/ЛҲstЙ’pЙҷКҠvЙҷr/","example_en":"We have a 6-hour stopover in Dubai.","example_ka":"бғ“бғЈбғ‘бғҗбғҳбғЁбғҳ 6-бғЎбғҗбғҗбғ—бғҳбғҗбғңбғҳ бғ’бғҗбғ©бғ”бғ бғ”бғ‘бғҗ бғ’бғ•бғҗбғҘбғ•бғЎ.","category":"travel-transport","level":"B1"},{"english":"direct","georgian":"бғһбғҳбғ бғ“бғҗбғһбғҳбғ бғҳ","pronunciation":"/daЙӘЛҲrekt/","example_en":"I prefer direct flights.","example_ka":"бғһбғҳбғ бғ“бғҗбғһбғҳбғ бғҳ бғ бғ”бғҳбғЎбғ”бғ‘бғҳ бғӣбғҳбғ бғ©бғ”бғ•бғңбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"non-stop","georgian":"бғЈбғ¬бғ§бғ•бғ”бғўбғҳ","pronunciation":"/ЛҢnЙ’n ЛҲstЙ’p/","example_en":"This is a non-stop flight to New York.","example_ka":"бғ”бғЎ бғңбғҳбғЈ-бғҳбғқбғ бғҷбғЁбғҳ бғЈбғ¬бғ§бғ•бғ”бғўбғҳ бғ бғ”бғҳбғЎбғҳбғҗ.","category":"travel-transport","level":"A2"},{"english":"cabin-crew","georgian":"бғ”бғҷбғҳбғһбғҗбғҹбғҳ","pronunciation":"/ЛҲkГҰbЙӘn kruЛҗ/","example_en":"The cabin crew was very helpful.","example_ka":"бғ”бғҷбғҳа°Әбғҗбғҹбғҳ бғ«бғҗбғҡбғҳбғҗбғң бғ—бғ•бғҗбғҡбғЎбғҗбғ©бғҳбғңбғқ бғҳбғ§бғқ.","category":"travel-transport","level":"B1"},{"english":"steward","georgian":"бғЎбғўбғҳбғЈбғҗбғ бғ“бғҳ","pronunciation":"/ЛҲstuЛҗЙҷrd/","example_en":"The steward served drinks during the flight.","example_ka":"бғЎбғўбғҳбғЈбғҗбғ бғ“бғӣбғҗ бғӨбғ бғ”бғңбғҳбғЎ бғ“бғ бғқбғЎ бғЎбғҗбғЎбғӣбғ”бғҡбғ”бғ‘бғҳ бғӣбғҳбғҗбғ бғ—бғ•бғҗ.","category":"travel-transport","level":"A2"},{"english":"stewardess","georgian":"бғЎбғўбғҳбғЈбғҗбғ бғ“бғ”бғЎбғҗ","pronunciation":"/ЛҢstuЛҗЙҷrЛҲdes/","example_en":"The stewardess demonstrated safety procedures.","example_ka":"бғЎбғўбғҳбғЈбғҗбғ бғ“бғ”бғЎбғҗбғӣ бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ”бғ‘бғҳбғЎ бғһбғ бғқбғӘбғ”бғ“бғЈбғ бғ”бғ‘бғҳ бғҗбғ©бғ•бғ”бғңбғҗ.","category":"travel-transport","level":"A2"},{"english":"oxygen","georgian":"бғҹбғҗбғңбғ’бғ‘бғҗбғ“бғҳ","pronunciation":"/ЛҲЙ’ksЙӘdК’Йҷn/","example_en":"Oxygen masks dropped from the ceiling.","example_ka":"бғҹбғҗбғңбғ’бғ‘бғҗбғ“бғҳбғЎ бғңбғҳбғҰбғ‘бғ”бғ‘бғҳ бғӯбғ”бғ бғҳбғ“бғҗбғң бғ©бғҗбғӣбғқбғ•бғҗбғ бғ“бғҗ.","category":"travel-transport","level":"B1"},{"english":"emergency","georgian":"бғ’бғҗбғңбғ’бғҗбғЁбғҳ","pronunciation":"/ЙӘЛҲmЙңЛҗrdК’Йҷnsi/","example_en":"Please locate the emergency exits.","example_ka":"бғ’бғ—бғ®бғқбғ•бғ—, бғ’бғҗбғңбғ’бғҗбғЁбғҳбғЎ бғ’бғҗбғӣбғқбғЎбғҗбғЎбғ•бғҡбғ”бғҡбғ”бғ‘бғҳ бғӣбғқбғңбғҗбғ®бғқбғ—.","category":"travel-transport","level":"A2"},{"english":"evacuation","georgian":"бғ”бғ•бғҗбғҷбғЈбғҗбғӘбғҳбғҗ","pronunciation":"/ЙӘЛҢvГҰkjuЛҲeЙӘКғЙҷn/","example_en":"The evacuation was completed safely.","example_ka":"бғ”бғ•бғҗбғҷбғЈбғҗбғӘбғҳбғҗ бғЈбғЎбғҗбғӨбғ бғ—бғ®бғқбғ“ бғ“бғҗбғЎбғ бғЈбғҡбғ“бғҗ.","category":"travel-transport","level":"B2"},{"english":"life-jacket","georgian":"бғЎбғҗбғӣбғҗбғЁбғ•бғ”бғҡбғқ бғҹбғҳбғҡбғ”бғўбғҳ","pronunciation":"/ЛҲlaЙӘf ЛҢdК’ГҰkЙӘt/","example_en":"Put on your life jacket in case of emergency.","example_ka":"бғ’бғҗбғңбғ’бғҗбғЁбғҳбғЎ бғЁбғ”бғӣбғ—бғ®бғ•бғ”бғ•бғҗбғЁбғҳ бғЎбғҗбғӣбғҗбғЁбғ•бғ”бғҡбғқ бғҹбғҳбғҡбғ”бғўбғҳ бғ©бғҗбғҳбғӘбғ•бғҳ.","category":"travel-transport","level":"B1"},{"english":"flotation","georgian":"бғӘбғЈбғ бғ•бғҳбғЎ бғЎбғҗбғЁбғЈбғҗбғҡбғ”бғ‘бғҗ","pronunciation":"/floКҠЛҲteЙӘКғЙҷn/","example_en":"Your seat can be used as a flotation device.","example_ka":"бғ—бғҘбғ•бғ”бғңбғҳ бғЎбғҷбғҗбғӣбғҳ бғӘбғЈбғ бғ•бғҳбғЎ бғЎбғҗбғЁбғЈбғҗбғҡбғ”бғ‘бғҗбғ“ бғЁбғ”бғҳбғ«бғҡбғ”бғ‘бғҗ бғ’бғҗбғӣбғқбғҳбғ§бғ”бғңбғқбғ—.","category":"travel-transport","level":"C1"},{"english":"altitude","georgian":"бғЎбғҳбғӣбғҗбғҰбғҡбғ”","pronunciation":"/ЛҲГҰltЙӘtuЛҗd/","example_en":"We're flying at cruising altitude.","example_ka":"бғ©бғ•бғ”бғң бғЎбғҗбғҷбғ бғЈбғҳбғ–бғқ бғЎбғҳбғӣбғҗбғҰбғҡбғ”бғ–бғ” бғ•бғӨбғ бғҳбғңбғҗбғ•бғ—.","category":"travel-transport","level":"B2"},{"english":"descent","georgian":"бғ“бғҗбғҰбғӣбғҗбғ бғўбғ”бғ‘бғҗ","pronunciation":"/dЙӘЛҲsent/","example_en":"The plane began its descent to the airport.","example_ka":"бғ—бғ•бғҳбғ—бғӣбғӨбғ бғҳбғңбғҗбғ•бғӣбғҗ бғҗбғ”бғ бғқбғһбғқбғ бғўбғҳбғЎбғҷбғ”бғң бғ“бғҗбғҰбғӣбғҗбғ бғўбғ”бғ‘бғҗ бғ“бғҗбғҳбғ¬бғ§бғқ.","category":"travel-transport","level":"B2"},{"english":"ascent","georgian":"бғҗбғҰбғӣбғҗбғ бғ—бғ”бғ‘бғҗ","pronunciation":"/ЙҷЛҲsent/","example_en":"The ascent was steeper than expected.","example_ka":"бғҗбғҰбғӣбғҗбғ бғ—бғ”бғ‘бғҗ бғӣбғқбғҡбғқбғ“бғҳбғңбғ–бғ” бғЈбғӨбғ бғқ бғӘбғҳбғӘбғҗбғ‘бғқ бғҳбғ§бғқ.","category":"travel-transport","level":"B2"},{"english":"crosswind","georgian":"бғҜбғ•бғҗбғ бғ”бғ“бғҳбғңбғҳ бғҘбғҗбғ бғҳ","pronunciation":"/ЛҲkrЙ’sЛҢwЙӘnd/","example_en":"Landing was difficult due to crosswinds.","example_ka":"бғҜбғ•бғҗбғ бғ”бғ“бғҳбғңбғҳ бғҘбғҗбғ бғҳбғЎ бғ’бғҗбғӣбғқ бғ“бғҗбғЁбғ•бғ”бғ‘бғҗ бғ бғ—бғЈбғҡбғҳ бғҳбғ§бғқ.","category":"travel-transport","level":"C1"},{"english":"headwind","georgian":"бғЎбғҗбғһбғҳбғ бғҳбғЎбғһбғҳбғ бғқ бғҘбғҗбғ бғҳ","pronunciation":"/ЛҲhedwЙӘnd/","example_en":"Strong headwinds delayed our arrival.","example_ka":"бғ«бғҡбғҳбғ”бғ бғӣбғҗ бғЎбғҗбғһбғҳбғ бғҳбғЎбғһбғҳбғ бғқ бғҘбғҗбғ бғӣбғҗ бғ©бғ•бғ”бғңбғҳ бғ©бғҗбғӣбғқбғЎбғ•бғҡбғҗ бғ“бғҗбғҗбғ’бғ•бғҳбғҗбғңбғҗ.","category":"travel-transport","level":"C1"},{"english":"tailwind","georgian":"бғҷбғЈбғ“бғЈбғҡбғҳ бғҘбғҗбғ бғҳ","pronunciation":"/ЛҲteЙӘlwЙӘnd/","example_en":"Tailwinds helped us arrive early.","example_ka":"бғҷбғЈбғ“бғЈбғҡбғӣбғҗ бғҘбғҗбғ бғӣбғҗ бғҗбғ“бғ бғ” бғ©бғҗбғӣбғқбғЎбғ•бғҡбғҗбғЁбғҳ бғ“бғҗбғ’бғ•бғ”бғ®бғӣбғҗбғ бғҗ.","category":"travel-transport","level":"C1"},{"english":"jet-lag","georgian":"бғ“бғ бғқбғҳбғЎ бғЎбғ¬бғ бғҗбғӨбғҳ бғӘбғ•бғҡбғҳбғҡбғ”бғ‘бғҳбғЎ бғЎбғҳбғңбғ“бғ бғқбғӣбғҳ","pronunciation":"/ЛҲdК’et lГҰЙЎ/","example_en":"I'm still suffering from jet lag.","example_ka":"бғҜбғ”бғ  бғҷбғҳбғ“бғ”бғ• бғ•бғҳбғўбғҗбғңбғҜбғ”бғ‘бғҳ бғ“бғ бғқбғҳбғЎ бғЎбғ¬бғ бғҗбғӨбғҳ бғӘбғ•бғҡбғҳбғҡбғ”бғ‘бғҳбғЎ бғЎбғҳбғңбғ“бғ бғқбғӣбғҳбғ—.","category":"travel-transport","level":"B2"},{"english":"timezone","georgian":"бғ“бғ бғқбғҳбғ—бғҳ бғ–бғқбғңбғҗ","pronunciation":"/ЛҲtaЙӘmzoКҠn/","example_en":"We crossed three timezones on this trip.","example_ka":"бғҗбғӣ бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҗбғ–бғ” бғЎбғҗбғӣбғҳ бғ“бғ бғқбғҳбғ—бғҳ бғ–бғқбғңбғҗ бғ’бғҗбғ“бғҗбғ•бғҷбғ•бғ”бғ—бғ”бғ—.","category":"travel-transport","level":"B1"},{"english":"adjustment","georgian":"бғЁбғ”бғ’бғЈбғ”бғ‘бғҗ","pronunciation":"/ЙҷЛҲdК’КҢstmЙҷnt/","example_en":"It takes time for adjustment to a new climate.","example_ka":"бғҗбғ®бғҗбғҡ бғҷбғҡбғҳбғӣбғҗбғўбғ—бғҗбғң бғЁбғ”бғ’бғЈбғ”бғ‘бғҗ бғ“бғ бғқбғЎ бғӣбғқбғҳбғ—бғ®бғқбғ•бғЎ.","category":"travel-transport","level":"B2"},{"english":"motion","georgian":"бғӣбғқбғ«бғ бғҗбғқбғ‘бғҗ","pronunciation":"/ЛҲmoКҠКғЙҷn/","example_en":"Some people get motion sickness on planes.","example_ka":"бғ–бғқбғ’бғҳбғ”бғ бғ— бғҗбғ“бғҗбғӣбғҳбғҗбғңбғЎ бғ—бғ•бғҳбғ—бғӣбғӨбғ бғҳбғңбғҗбғ•бғЁбғҳ бғӣбғқбғ«бғ бғҗбғқбғ‘бғҳбғЎ бғЎбғҳбғ‘бғ бғҗбғҡбғЈбғҡбғ” бғ”бғ‘бғҗбғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"A2"},{"english":"sickness","georgian":"бғЎбғҳбғ‘бғ бғҗбғҡбғЈбғҡбғ”","pronunciation":"/ЛҲsЙӘknЙҷs/","example_en":"Take medication for motion sickness.","example_ka":"бғӣбғқбғ«бғ бғҗбғқбғ‘бғҳбғЎ бғЎбғҳбғ‘бғ бғҗбғҡбғЈбғҡбғ”бғ–бғ” бғ¬бғҗбғӣбғҗбғҡбғҳ бғӣбғҳбғҳбғҰбғ”.","category":"travel-transport","level":"A2"},{"english":"nausea","georgian":"бғ’бғЈбғҡбғҳбғЎбғ бғ”бғ•бғҗ","pronunciation":"/ЛҲnЙ”ЛҗziЙҷ/","example_en":"The turbulence caused nausea.","example_ka":"бғўбғЈбғ бғ‘бғЈбғҡбғ”бғңбғўбғқбғ‘бғҗбғӣ бғ’бғЈбғҡбғҳбғЎбғ бғ”бғ•бғҗ бғ’бғҗбғӣбғқбғҳбғ¬бғ•бғҳбғҗ.","category":"travel-transport","level":"B2"},{"english":"seasick","georgian":"бғ–бғҰбғ•бғҳбғЎ бғ‘бғ бғҗбғҡбғЈбғҡбғҳ","pronunciation":"/ЛҲsiЛҗsЙӘk/","example_en":"Many passengers felt seasick during the storm.","example_ka":"бғҘбғҗбғ бғҳбғЁбғ®бғҡбғҳбғЎ бғ“бғ бғқбғЎ бғ‘бғ”бғ•бғ бғҳ бғӣбғ’бғ–бғҗбғ•бғ бғҳ бғ–бғҰбғ•бғҳбғЎ бғ‘бғ бғҗбғҡбғЈбғҡбғҳ бғҳбғ§бғқ.","category":"travel-transport","level":"B1"},{"english":"airsick","georgian":"бғ°бғҗбғ”бғ бғҳбғЎ бғ‘бғ бғҗбғҡбғЈбғҡбғҳ","pronunciation":"/ЛҲeЙҷrsЙӘk/","example_en":"She gets airsick on long flights.","example_ka":"бғҳбғЎ бғ’бғ бғ«бғ”бғҡ бғӨбғ бғ”бғңбғ”бғ‘бғ–бғ” бғ°бғҗбғ”бғ бғҳбғЎ бғ‘бғ бғҗбғҡбғЈбғҡбғҳ бғ®бғ“бғ”бғ‘бғҗ.","category":"travel-transport","level":"B1"},{"english":"carsick","georgian":"бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғ‘бғ бғҗбғҡбғЈбғҡбғҳ","pronunciation":"/ЛҲkЙ‘ЛҗrsЙӘk/","example_en":"Children often get carsick on winding roads.","example_ka":"бғ‘бғҗбғ•бғЁбғ•бғ”бғ‘бғҳ бғ®бғЁбғҳбғ бғҗбғ“ бғ®бғ•бғ”бғЈбғҡбғҳ бғ’бғ–бғ”бғ‘бғ–бғ” бғӣбғҗбғңбғҘбғҗбғңбғҳбғЎ бғ‘бғ бғҗбғҡбғЈбғҡбғ”бғ‘бғҳ бғ®бғ“бғ”бғ‘бғҳбғҗбғң.","category":"travel-transport","level":"A2"},{"english":"medication","georgian":"бғ¬бғҗбғӣбғҗбғҡбғҳ","pronunciation":"/ЛҢmedЙӘЛҲkeЙӘКғЙҷn/","example_en":"Pack your medication in carry-on luggage.","example_ka":"бғ¬бғҗбғӣбғҗбғҡбғҳ бғ®бғ”бғҡ бғ‘бғҗбғ бғ’бғЁбғҳ бғ©бғҗбғҡбғҗбғ’бғ”.","category":"travel-transport","level":"A2"},{"english":"prescription","georgian":"бғ бғ”бғӘбғ”бғһбғўбғҳ","pronunciation":"/prЙӘЛҲskrЙӘpКғЙҷn/","example_en":"Bring a prescription for your medication.","example_ka":"бғ¬бғҗбғӣбғҡбғҳбғЎбғ—бғ•бғҳбғЎ бғ бғ”бғӘбғ”бғһбғўбғҳ бғ©бғҗбғӣбғқбғҳбғўбғҗбғңбғ”.","category":"travel-transport","level":"B1"},{"english":"vaccination","georgian":"бғ•бғҗбғҘбғӘбғҳбғңбғҗбғӘбғҳбғҗ","pronunciation":"/ЛҢvГҰksЙӘЛҲneЙӘКғЙҷn/","example_en":"Some countries require vaccination certificates.","example_ka":"бғ–бғқбғ’бғҳбғ”бғ бғ— бғҘбғ•бғ”бғ§бғҗбғңбғҗбғЁбғҳ бғ•бғҗбғҘбғӘбғҳбғңбғҗбғӘбғҳбғҳбғЎ бғЎбғ”бғ бғўбғҳбғӨбғҳбғҷбғҗбғўбғ”бғ‘бғҳ бғҗбғ бғҳбғЎ бғЎбғҗбғӯбғҳбғ бғқ.","category":"travel-transport","level":"B2"},{"english":"certificate","georgian":"бғЎбғ”бғ бғўбғҳбғӨбғҳбғҷбғҗбғўбғҳ","pronunciation":"/sЙҷrЛҲtЙӘfЙӘkЙҷt/","example_en":"Show your health certificate at the border.","example_ka":"бғЎбғҗбғ–бғҰбғ•бғҗбғ бғ—бғҗбғң бғҜбғҗбғңбғӣбғ бғ—бғ”бғҡбғқбғ‘бғҳбғЎ бғЎбғ”бғ бғўбғҳбғӨбғҳбғҷбғҗбғўбғҳ бғҗбғ©бғ•бғ”бғңбғ”.","category":"travel-transport","level":"B1"},{"english":"document","georgian":"бғ“бғқбғҷбғЈбғӣбғ”бғңбғўбғҳ","pronunciation":"/ЛҲdЙ’kjumЙҷnt/","example_en":"Keep all travel documents together.","example_ka":"бғ§бғ•бғ”бғҡбғҗ бғЎбғҗбғӣбғқбғ’бғ–бғҗбғЈбғ бғқ бғ“бғқбғҷбғЈбғӣбғ”бғңбғўбғҳ бғ”бғ бғ—бғҗбғ“ бғЁбғ”бғҳбғңбғҗбғ®бғ”.","category":"travel-transport","level":"A2"},{"english":"identification","georgian":"бғӣбғқбғ¬бғӣбғқбғ‘бғҗ","pronunciation":"/aЙӘЛҢdentЙӘfЙӘЛҲkeЙӘКғЙҷn/","example_en":"Valid identification is required for travel.","example_ka":"бғӣбғқбғ’бғ–бғҗбғЈбғ бғқбғ‘бғҳбғЎбғ—бғ•бғҳбғЎ бғ«бғҗбғҡбғҗбғЁбғҳ бғӣбғ§бғқбғӨбғҳ бғӣбғқбғ¬бғӣбғқбғ‘бғҗ бғҗбғ бғҳбғЎ бғЎбғҗбғӯбғҳбғ бғқ.","category":"travel-transport","level":"B1"},{"english":"authority","georgian":"бғЈбғ¬бғ§бғ”бғ‘бғҗ","pronunciation":"/Й”ЛҗЛҲОёЙ”ЛҗrЙҷti/","example_en":"Contact the immigration authorities.","example_ka":"бғҳбғӣбғҳбғ’бғ бғҗбғӘбғҳбғҳбғЎ бғЈбғ¬бғ§бғ”бғ‘бғҗбғЎбғ—бғҗбғң бғ“бғҗбғЈбғҷбғҗбғ•бғЁбғҳбғ бғ“бғҳ.","category":"travel-transport","level":"B1"}]`);export{e as default};
